void main();

#define KSTACKSIZE 4 * PGSIZE
// entry.S needs one stack per CPU.
__attribute__((aligned(16))) char stack0[KSTACKSIZE * NCPU];

// 打印页表启用时的缺页信息
void boot_trap() {
  sfence_vma();
  w_satp(0);
  sfence_vma();
	uint64 sepc = r_sepc();    // 获取导致异常的指令地址
  uint64 stval = r_stval();  // 获取试图访问的缺页地址
  uint64 scause = r_scause(); // 获取异常原因
  printf("scause %p\n", scause);
  printf("sepc=%p stval=%p\n", sepc, stval);
  panic("kerneltrap");
}

// entry.S jumps here in machine mode on stack0.
void start(long hartid) {

  // Supervisor: disable paging for now.
  w_satp(0);

  // enable some supervisor interrupt
  w_sie(r_sie() | SIE_SEIE | SIE_STIE);

  // save hartid
  w_tp(hartid);

  // enable supervisor mode deref user pointers.
  w_sstatus(r_sstatus() | SSTATUS_SUM);
  w_stvec((uint64)boot_trap);

  main();
}

