void logo() {
  printf("\n");
  printf("8.8888        8          .8.    8888888.8888888888 ,o888888o.       "
         "d888888o.   \n");
  printf("8.8888        8         .888.         8.8888    ..8888     `88.   "
         ".`8888:' `88. \n");
  printf("8.8888        8        :88888.        8.8888   ,8.8888       `8b  "
         "8.`8888.   Y8 \n");
  printf("8.8888        8       ..`88888.       8.8888   88.8888        `8b "
         "`8.`8888.    \n");
  printf("8.8888        8      .8..`88888.      8.8888   88.8888         88  "
         "`8.`8888.   \n");
  printf("8.8888        8     .8`8..`88888.     8.8888   88.8888         88   "
         "`8.`8888.  \n");
  printf("8.8888888888888    .8' `8..`88888.    8.8888   88.8888        ,8P    "
         "`8.`8888.  \n");
  printf("8.8888        8   .8'   `8..`88888.   8.8888   `8.8888       ,8P 8b  "
         " `8.`8888. \n");
  printf("8.8888        8  .888888888..`88888.  8.8888    `.8888     ,88'  "
         "`8b.  ;8.`8888 \n");
  printf("8.8888        8 .8'       `8..`88888. 8.8888       `8888888P'     "
         "`Y8888P.,88P' \n");
  printf("\n");
}
// start() jumps here in supervisor mode on all CPUs.
void main() {
  if (started == 0) {
    started = 1;
    int cpui = cpuid();
    consoleinit();
    printfinit();
    // logo();
    kinit();        // physical page allocator
    printf("kmm initialized\n");
    kvminit();        // create kernel page table
    printf("vmm initialized\n");

    printf("kernpagetable : %p\n",kern_pagetable);

    kvminithart();        // turn on paging
    kmmfix();
    checkpc();
    __sync_synchronize();
    printf("hart %d kernel pagetable enabled\n", cpui);
    procinit();        // process table
    printf("process info initialized\n");
    trapinit();        // trap vectors
    printf("trap initialized\n");
    trapinithart();        // install kernel trap vector
    printf("hart %d trap enabled\n", cpui);
    //uartinit();
    plicinit();            // set up interrupt controller
    plicinithart();        // ask PLIC for device interrupts
    fsinit();              // init some fs modules, except for reading disk.
    userinit();            // first user process
    __sync_synchronize();
    for (int i = 0; i < NCPU; i++) {
      if (i == cpuid())
        continue;
      SBI_HART_START(i, 0x80200000, 0);
    }
    __sync_synchronize();
    printf("hart %d started\n", cpui);
  } else {
    __sync_synchronize();
    int cpui = cpuid();
    printf("hart %d starting\n", cpui);
    kvminithart();        // turn on paging
    checkpc();
    __sync_synchronize();
    printf("hart %d kernel pagetable enabled\n", cpui);
    trapinithart();        // install kernel trap vector
    printf("hart %d trap enabled\n", cpui);
    plicinithart();        // ask PLIC for device interrupts
    printf("hart %d started\n", cpui);
  }
  scheduler();
}

