#include "types.h"
#include "param.h"
#include "riscv.h"
#include "memlayout.h"
#include "lib/locks.h"
#include "defs.h"
#include "lib/buddy.h"

// PIC compile.
// so even if the kpgtbl is enabled
// the global variables and function addrs will not change
// but this module sometimes uses pa, needs to add KVMOFFSET
// xv6注解：这里的run实际上将next信息写入了页面对应的物理地址页面首8字节中。
//所以为了在虚拟地址环境下运行，应当把r改为对应虚拟地址。

extern char end[];

struct {
  struct spinlock lock;
  uint8 cnt[(PHYSTOP - PHYBASE) / PGSIZE];        // 引用计数
} Refmap;

struct run {
  struct run *next;
};

struct kmem {
  struct spinlock lock;
  struct run *freelist;
  int freepage;
} kmem;

void kinit() {
  initlock(&kmem.lock, "kmem");
  initlock(&Refmap.lock, "Refmap");
  kmem.freepage = 0;
  char *p;
  p = (char *)PGROUNDUP((uint64)end);
  for (; p + PGSIZE <= (char *)PHYSTOP; p += PGSIZE) {
    struct run *r = (struct run *)p;
    r->next = kmem.freelist;
    kmem.freelist = r;
    kmem.freepage++;
  }
}

int PgCheck(void *oa, int flag) {
  uint64 pa = (uint64)oa - KVMOFFSET;
  if ((pa % PGSIZE) != 0 || (uint64)oa < (uint64)end || pa >= PHYSTOP) {
    if (flag == 1) {
      printf("%p", oa);
      panic("PgCheck error");
    } else
      return 0;
  }
  return 1;
}

void *PgAlloc() {
  struct run *r;
  void *va;
  acquire(&kmem.lock);
  r = kmem.freelist;
  if (r) {
    kmem.freelist = r->next;
    kmem.freepage--;
  }
  release(&kmem.lock);

  if (r) {
    va = (void *)r;
    memset((char *)va, 0, PGSIZE);

    uint64 bitindex;
    if ((uint64)r > KVMOFFSET)
      bitindex = ((uint64)r - VIRTBASE) / PGSIZE;
    else
      bitindex = ((uint64)r - PHYBASE) / PGSIZE;
    acquire(&Refmap.lock);
    Refmap.cnt[bitindex] = 1;        // 将引用计数初始化为1
    release(&Refmap.lock);
  }
  return (void *)r;
}

void PgFree(void *oa) {
  struct run *r;
  r = (struct run *)oa;
  if ((uint64)oa > KVMOFFSET)
    PgCheck(oa, 1);

  uint64 bitindex;
  if ((uint64)r > KVMOFFSET)
    bitindex = ((uint64)r - VIRTBASE) / PGSIZE;
  else
    bitindex = ((uint64)r - PHYBASE) / PGSIZE;
  acquire(&Refmap.lock);
  Refmap.cnt[bitindex]--;
  if (Refmap.cnt[bitindex] == 0) {
    release(&Refmap.lock);
    acquire(&kmem.lock);
    r->next = kmem.freelist;
    kmem.freelist = r;
    kmem.freepage++;
    release(&kmem.lock);
  } else
    release(&Refmap.lock);
}

// using oa, only calls after kpgtbl started
uint8 PgGetRefCnt(void *oa) {
  uint8 ret;
  uint64 bitindex = ((uint64)oa - VIRTBASE) / PGSIZE;
  acquire(&Refmap.lock);
  ret = Refmap.cnt[bitindex];
  release(&Refmap.lock);
  return ret;
}
void PgAddRefCnt(void *oa) {
  uint64 bitindex = ((uint64)oa - VIRTBASE) / PGSIZE;
  acquire(&Refmap.lock);
  Refmap.cnt[bitindex]++;
  release(&Refmap.lock);
}
inline uint64 GetFreeMemSize() {
  int freecnt = kmem.freepage;
  return (uint64)PGSIZE * freecnt;
}

extern struct buddy_pool buddy_pool;

struct spinlock buddylock;

struct buddy *CrtBuddy(int level, void *tree, void *mem) {
  // 4096 Byte
  struct buddy *b = buddy_new(level, tree, mem);
  return b;
}

int DltBuddy(struct buddy *b) {
  if (b < &buddy_pool.buddy[0] || b >= &buddy_pool.buddy[NBUDDYPOOL])
    return ERR;
  buddy_delete(b);
  return 0;
}

void *kmalloc(struct buddy *b, int size) {
  if (size <= 0 || b < &buddy_pool.buddy[0] ||
      b >= &buddy_pool.buddy[NBUDDYPOOL])
    return NULL;
  acquire(&buddylock);
  int offset = buddy_alloc(b, size);
  release(&buddylock);
  if (offset == -1)
    return NULL;
  memset(b->mem + offset, 0, size);
  return b->mem + offset;
}

void kfree(struct buddy *b, void *obj) {
  uint64 offset = (uint64)obj - (uint64)b->mem;
  if (offset > (1 << b->level) || b < &buddy_pool.buddy[0] ||
      b >= &buddy_pool.buddy[NBUDDYPOOL])
    return;
  acquire(&buddylock);
  int size = buddy_size(b, (int)offset);
  release(&buddylock);
  memset(obj, 0, size);
  acquire(&buddylock);
  buddy_free(b, (int)offset);
  release(&buddylock);
}

void *kcalloc(struct buddy *b, uint64 size, int times) {
  if (times == 1)
    return kmalloc(b, size);
  else
    panic("kcalloc: not implemented times above 1");
}

