// sv39, 3-level page table

pagetable_t kern_pagetable;        //使用物理地址
pte_t kern_page;
pte_t drive_page;
pte_t kstack_page;
pte_t trampoline_page;
pte_t vf2sbi_page;

extern char etext[];
extern char user_sig_return[];
int kpgtblstarted;        //标记页表是否启用，kmm.c使用。


void kvminit(void) {
  pagetable_t kpgtbl;

  kpgtbl = (pagetable_t)PgAlloc();
  memset(kpgtbl, 0, PGSIZE);

  // uart registers
  kvmmap(kpgtbl, UART0 + KDRIVEBASE, UART0, PGSIZE, PTE_R | PTE_W | PTE_G);

  // virtio mmio disk interface
  kvmmap(kpgtbl, VIRTIO0 + KDRIVEBASE, VIRTIO0, PGSIZE, PTE_R | PTE_W | PTE_G);
  // SPI
  kvmmap(kpgtbl, SPI0 + KDRIVEBASE, SPI0, PGSIZE, PTE_R | PTE_W | PTE_G);

  // PLIC
  kvmmap(kpgtbl, PLIC + KDRIVEBASE, PLIC, 0x400000, PTE_R | PTE_W | PTE_G) ;

  // map kernel text executable and read-only.
  kvmmap(kpgtbl, VIRTBASE, PHYBASE, (uint64)etext - PHYBASE, PTE_R | PTE_X | PTE_G);

  // map kernel data and the physical RAM we'll make use of.
  kvmmap(kpgtbl, (uint64)etext + KVMOFFSET, (uint64)etext,
         PHYSTOP - (uint64)etext, PTE_R | PTE_W | PTE_G);

  // map VisionFive2 SBI address
  kvmmap(kpgtbl, KDRIVEBASE + VF2_SBIBASE, VF2_SBIBASE,
         0X200000, PTE_R | PTE_W | PTE_G | PTE_X);

  kvmmap(kpgtbl, VF2_SBIBASE, VF2_SBIBASE,
         0X200000, PTE_R | PTE_W | PTE_G | PTE_X);

  //kvmmap(kpgtbl, SPI_CTRL, SPI_CTRL, PGSIZE, PTE_R | PTE_W | PTE_G);
  kvmmap(kpgtbl, PLIC, PLIC, 0x400000, PTE_R | PTE_W | PTE_G) ;

  // allocate and map a kernel stack for each process.
  proc_kstacks(kpgtbl);

  // map the direct map part.
  kvmmap(kpgtbl, PHYBASE, PHYBASE, (uint64)etext - PHYBASE, PTE_R | PTE_X);
  kvmmap(kpgtbl, (uint64)etext, (uint64)etext, PHYSTOP - (uint64)etext,
         PTE_R | PTE_W);

  kvmmap(kpgtbl, SIGNAL_TRAMPOLINE, (uint64)user_sig_return, PGSIZE,
         PTE_R | PTE_X | PTE_U | PTE_G);

  kern_pagetable = kpgtbl;

  // Save the kernpages and label them PTE_G, for better performance in tlb
  // flush
  kern_page = *(&kern_pagetable[PX(2, VIRTBASE)]);
  drive_page = *(&kern_pagetable[PX(2, KDRIVEBASE)]);
  kstack_page = *(&kern_pagetable[PX(2, KSTACKSTOP)]);
  trampoline_page = *(&kern_pagetable[PX(2, UTRAMPOLINEBASE)]);

  vf2sbi_page = *(&kern_pagetable[PX(2, VF2_SBIBASE)]);
}

void kvminithart() {
  sfence_vma();
  w_satp(MAKE_SATP(kern_pagetable));

  // enables virtual kernel address
  sfence_vma();
  kvmfix();
  sfence_vma();

  kpgtblstarted = 1;

  __sync_synchronize();
}
// PtWalk a addr for a pgtbl.
pte_t *PtWalk(pagetable_t pagetable, uint64 va, int alloc) {
  if (va >= MAXVA)
    panic("PtWalk");

  pte_t *pte;
  for (int level = 2; level > 0; level--) {
    pte = &pagetable[PX(level, va)];
    if (*pte & PTE_V) {
      if (kpgtblstarted)
        pagetable = (pagetable_t)(PTE2PA(*pte) + KVMOFFSET);
      else
        pagetable = (pagetable_t)PTE2PA(*pte);
    } else {
      if (!alloc || (pagetable = (pde_t *)PgAlloc()) == 0)
        return 0;
      if (kpgtblstarted)
        *pte = PA2PTE((uint64)pagetable - KVMOFFSET) | PTE_V;
      else
        *pte = PA2PTE(pagetable) | PTE_V;
    }
  }
  return &pagetable[PX(0, va)];
