// Look up a virtual address, return the kernel virtual physical address,
// or 0 if not mapped.
// Can only be used to look up user pages.
// modify: also returns oa.
uint64 PtGetAddr(pagetable_t pagetable, uint64 va) {
  pte_t *pte;
  uint64 pa;

  if (va >= MAXVA)
    return 0;

  pte = PtWalk(pagetable, va, 0);
  if (pte == 0)
    return 0;
  if ((*pte & PTE_V) == 0)
    return 0;
  if ((*pte & PTE_U) == 0)
    return 0;
  pa = PTE2PA(*pte);
  return (pa + KVMOFFSET);
}

// Create PTEs for virtual addresses starting at va that refer to
// physical addresses starting at pa. va and size might not
// be page-aligned. Returns 0 on success, -1 if PtWalk() couldn't
// allocate a needed page-table page.
// uses oa(kpgtbl va) instead of va
int PtMapPage(pagetable_t pagetable, uint64 va, uint64 oa, int perm) {
  uint64 a;
  pte_t *pte;
  assert(oa % PGSIZE == 0);

  a = PGROUNDDOWN(va);
  uint64 pa = oa - KVMOFFSET;
  if ((pte = PtWalk(pagetable, a, 1)) == 0)
    return -1;
  if ((*pte & PTE_V) && PTE2PA(*pte)) {
    printf("%x\n", va);
    panic("PtMapPage: remap");
  }
  *pte = PA2PTE(pa) | perm | PTE_V | PTE_A | PTE_D;

  return 0;
}

// 分配页表项到PD（1x）层级上，但不分配叶页面。（缺页时分配）
int PtLazyMap(pagetable_t pagetable, uint64 va, uint64 len) {
  assert((va % PGSIZE == 0) && (len % PGSIZE) == 0);
  uint64 vastart = PGROUNDDOWN_1X(va);
  uint64 vaend = PGROUNDUP_1X(va + len);
  uint64 va_i = vastart;
  pte_t *pte;
  pagetable_t pti;
  for (; va_i < vaend; va_i += PGSIZE_1X) {
    pti = pagetable;
    for (int level = 2; level > 0; level--) {
      pte = &pti[PX(level, va_i)];
      if (*pte & PTE_V) {
        pti = (pagetable_t)(PTE2PA(*pte) + KVMOFFSET);
      } else {
        if ((pti = (pde_t *)PgAlloc()) == 0)
          return ERR;
        *pte = PA2PTE((uint64)pti - KVMOFFSET) | PTE_V;
      }
    }
  }
  return 0;
}

