void PtLazyCopy(pagetable_t srcupt, pagetable_t dstupt, uint64 va, uint64 len) {
  uint64 vastart = PGROUNDDOWN_1X(va);
  uint64 vaend = PGROUNDUP_1X(va + len);
  uint64 va_i = vastart;
  pte_t *srcpte;
  pte_t *dstpte;
  pagetable_t src_pti;
  pagetable_t dst_pti;
  for (; va_i < vaend; va_i += PGSIZE_1X) {
    src_pti = srcupt;
    dst_pti = dstupt;
    for (int level = 2; level > 1; level--) {
      srcpte = &src_pti[PX(level, va)];
      dstpte = &dst_pti[PX(level, va)];
      if (*dstpte & PTE_V) {
        dst_pti = (pagetable_t)(PTE2PA(*dstpte) + KVMOFFSET);
      } else {
        if ((dst_pti = (pde_t *)PgAlloc()) == 0)
          panic("ptlazycopy : no mem!");
        memset(dst_pti, 0, PGSIZE);
        *dstpte = PA2PTE((uint64)dst_pti - KVMOFFSET) | PTE_V;
      }
      src_pti = (pagetable_t)(PTE2PA(*srcpte) + KVMOFFSET);
    }
    srcpte = &src_pti[PX(1, va)];
    dstpte = &dst_pti[PX(1, va)];
    uint64 pgoa = PTE2PA(*srcpte) + KVMOFFSET;
    PgAddRefCnt((void*)pgoa);
    *dstpte = *srcpte;
  }
