// umm.c
// handles user heap addrspace alloc like mmap
// and allocs user heap memory. some syscall buffer asks for this.

struct buddy *MapBuddy;
uint8 MapBuddyTree[PGSIZE * 16] __attribute__((aligned(PGSIZE)));
uint8 MapBuddyMem[PGSIZE * 8] __attribute__((aligned(PGSIZE)));

// alloc Text&Data&Stack mem for user proc.
// name style refers from xv6, but function differs a bit.
// used in exec, brk syscall, works also as init of a proc.
// pos & size must be PAGE-ALIGNED. pos is the addr.
uint64 uvmalloc(pagetable_t pagetable, uint64 pos, uint64 size, uint64 perm) {
  char *mem;
  uint64 a;
  if (size == 0)
    return 0;
  uint64 start = PGROUNDDOWN(pos);
  uint64 end = PGROUNDUP(pos + size);
  for (a = start; a < end; a += PGSIZE) {
    pte_t *pte = PtWalk(pagetable, a, 0);
    if (pte != 0 && *pte != 0)
      continue;
    mem = PgAlloc();
    if (mem == 0) {
      PtUnMapPages(pagetable, pos, (a - pos) / PGSIZE, 1);
      return 0;
    }
    memset(mem, 0, PGSIZE);
    if (PtMapPage(pagetable, a, (uint64)mem, PTE_R | PTE_U | perm) != 0) {
      PgFree(mem);
      PtUnMapPages(pagetable, pos, (a - pos) / PGSIZE, 1);
      return 0;
    }
  }
  uint64 real_size = PGROUNDUP(size + pos) - PGROUNDDOWN(pos);
  return real_size;
}

// fork() calls to copy-on-write fork the memory
int uvmcopy(pagetable_t old, pagetable_t new, uint64 sz) {
  pte_t *pte;
  uint64 oa, i, pa;
  uint flags;
  uint64 startaddr[2] = {UVMBASE, USTACKSTOP};
  uint64 endaddr[2];
  endaddr[0] = sz + UVMBASE;
  endaddr[1] = USTACKBASE;

  for (int j = 0; j < 2; j++) {
    for (i = startaddr[j]; i < endaddr[j]; i += PGSIZE) {
      pte = PtWalk(old, i, 0);
      if (pte == 0 || *pte == 0)
        continue;
      if ((*pte & PTE_V) == 0)
        panic("uvmcopy: page not present");
      pa = PTE2PA(*pte);
      oa = pa + KVMOFFSET;
      flags = PTE_FLAGS(*pte);

      // 仅对可写页面设置COW标记
      if (flags & PTE_W) {
        // 禁用写并设置COW Fork标记
        flags = (flags | PTE_COW) & ~PTE_W;
        *pte = PA2PTE(pa) | flags;
      }

      if (PtMapPage(new, i, oa, flags) != 0) {
        return -1;
      }
      // 增加内存的引用计数
      PgAddRefCnt((char *)oa);
    }
  }
  return 0;
}

