static mapregion_t *MapAlloc(uint64 start, uint64 size, uint64 flags,
                          uint64 prot) {
  void *mapoa = kmalloc(MapBuddy, sizeof(mapregion_t));
  if (mapoa == 0)
    return NULL;
  mapregion_t *newmap = (mapregion_t *)mapoa;
  newmap->start = start;
  newmap->size = size;
  newmap->valid = 1;
  newmap->flags = flags;
  newmap->prot = prot;
  return newmap;
}

static void MapFree(mapregion_t *map) {
  map->valid = 0;
  kfree(MapBuddy, map);
