static void MapFreeArea(pagetable_t upt, mapregion_t* map, uint64 start, uint64 end){
  if(map->flags & MAP_SHM)
    return;
  uint64 mapstart = map->start;
  uint64 mapend = mapstart + map->size;
  if(map->flags & MAP_SHARED){
    if(start > mapstart)
      start = PGROUNDDOWN_1X(start);
    if(end < mapend)
      end = PGROUNDDOWN_1X(end);
  }
  if(start >= end)
    return;
  start = MAX(start,mapstart);
  end = MIN(end,mapend);
  uint64 freestart = PGROUNDDOWN_1X(start);
  uint64 freeend = PGROUNDUP_1X(end);
  for(uint64 i = freestart; i < freeend; i += PGSIZE_1X)
    PtLazyUnmap(upt,i);
}

