static void MapSync(mapregion_t *map, uint64 start, uint64 endaddr) {
  // MAP_PRIVATE与MAP_ANONYMOUS则无视此操作
  if (map->flags & MAP_PRIVATE || map->flags & MAP_ANONYMOUS)
    return;
  pagetable_t upt = getproc()->pagetable;
  uint64 mapstart = start ? map->start : MAX(map->start, start);
  uint64 mapend = endaddr ? mapstart + map->size : MIN(mapstart + map->size, endaddr);
  assert(map->mapfile != NULL);
  for (uint64 i = mapstart; i < mapend; i += PGSIZE) {
    pte_t *pte = PtWalk(upt, i, 0);
    if (pte == NULL)
      i = PGROUNDUP(i + 1);
    if (*pte & PTE_U && *pte & PTE_D) {
      uint64 offset = map->offset + i - mapstart;
      general_filewrite(map->mapfile, i, offset + i-mapstart, PGSIZE);
    }
  }
}

static bool MapInArea(mapregion_t *map, uint64 start, uint64 end) {
  if (end <= map->start)
    return 0;
  if (start >= map->start + map->size)
    return 0;
  return 1;
}

static void MapProtect(mapregion_t *map, uint64 start, uint64 endaddr,
                       uint64 prot) {
  uint64 mapstart = MAX(map->start, start);
  uint64 mapend = MIN(map->start + map->size, endaddr);
  map->prot = prot;
  map->start = mapstart;
  map->size = mapend - map->start;
  assert(map->size > 0);
}

// start is used in mmap, it labels a reference to start.
// if start is lower than UMAPBASE, it will be set higher than that.
// returns the new mapregion_t. start & size is PAGE-ALIGNED
/// @note 实际分配会按照PGSIZE_1X对齐
void *proc_mapspace(uint64 start, uint64 size, int flags, int prot) {
  struct proc* p = getproc();
  mapregion_t *map = NULL;
  //地址检查
  bool maplabel = 1;
  if (start < UMAPBASE || start + size > UMAPSTOP)
    start = UMAPBASE;
  if (size > UMAPSTOP - UMAPBASE)
    return 0;
  assert(start >= UMAPBASE && start < UMAPSTOP);
  uint64 align_start = PGROUNDDOWN_1X(start);
  uint64 align_end = PGROUNDUP_1X(start + size);
  TAILQ_FOREACH(map, &p->umaphead, node){
    if(MapInArea(map, align_start, align_end))
      maplabel = 0;
  }

  uint64 prev_end = UMAPBASE;
  TAILQ_FOREACH(map, &p->umaphead, node) {
    uint64 pstart = map->start;
    uint64 pend = pstart + map->size;
    // 未指定起始地址或指定失效，找到合适区间
    if (maplabel == 0 && pstart - prev_end > size)
      break;
    // 指定起始地址上找到第一个大于start的地址
    if (maplabel == 1 && pstart > start) 
      break;
    prev_end = PGROUNDUP_1X(pend);
  }

  uint64 newstart;
  if (maplabel == 1)
    newstart = start;
  else
    newstart = prev_end;
  mapregion_t *newmap = MapAlloc(newstart, size, flags, prot);
  // map may be null
  TAILQ_INSERT_AFTER_SAFE(&p->umaphead, map, newmap, node);
  return newmap;
}

int proc_unmapspace(struct proc *p, uint64 start, uint64 size) {
  mapregion_t *map = NULL;
  mapregion_t *next = NULL;
  mapregion_t *prevmap = NULL;
  uint64 end = start + size;

  TAILQ_FOREACH_SAFE(map, &p->umaphead, node, next) {
    uint64 mapstart = map->start;
    uint64 mapend = mapstart + map->size;
    if (MapInArea(map,start,end)) {
      //删除旧有mapspace
      TAILQ_REMOVE(&p->umaphead, map, node);
      MapSync(map, start, end);
      uint64 flags = map->flags;
      uint64 prot = map->prot;
      MapFreeArea(p->pagetable,map,start,end);
      MapFree(map);
      map = NULL;
      //起始地址不覆盖，新建一个mapregion
      if (start > mapstart) {
        uint64 size = start - mapstart;
        mapregion_t *newmap = MapAlloc(mapstart, size, flags, prot);
        TAILQ_INSERT_AFTER_SAFE(&p->umaphead, prevmap, newmap, node);
        prevmap = newmap;
      }
      //终止地址不覆盖，新建一个mapregion
      if (end < mapend) {
        uint64 size = mapend - end;
        mapregion_t *newmap = MapAlloc(end, size, flags, prot);
        TAILQ_INSERT_AFTER_SAFE(&p->umaphead, prevmap, newmap, node);
        prevmap = newmap;
      }
    }
    if(map)
      prevmap = map;
  }
  return 0;
}

void proc_mapfree(struct proc *p) {
  pagetable_t upt = p->pagetable;
  mapregion_t *map = NULL;
  mapregion_t *next = NULL;
  TAILQ_FOREACH_SAFE(map, &p->umaphead, node, next) {
    // 调用msync会带锁睡觉（然后死锁或重复获取锁）。所以不能调用
    //msync(UMAPBASE,UMAPSTOP-UMAPBASE,0);
    MapUptFree(upt, map);
  }
}

