// mmap懒分配。
int mmaprw(uint64 va, int scause) {
  int retval = ERR;
  struct proc *p = getproc();
  mapregion_t *map;

  //搜索缺页地址区间
  TAILQ_FOREACH(map, &p->umaphead, node) {
    uint64 startva = map->start;
    uint64 endva = startva + map->size;
    //确定了所属map范围
    if (va >= startva && va < endva) {
      //检查缺页类型是否匹配读写权限。
      retval = MapCheckCause(map, scause);
      if (retval != 0)
        return ERR;
      pte_t* pte = PtWalk(p->pagetable,va,0);
      //若已有映射则更新页表权限。
      if(pte != 0 && *pte != 0){
        uint64 newflag = UpdateFlag(map);
        *pte = *pte | newflag;
        retval = 0;
      }
      else 
        retval = MapReadPage(map, va);
      break;
    }
  }
  return retval;
}

