inline void kvmfix() {
  // add kvmoffset to sp & fp & saved ra
  // this func runs only a single stackframe above main()
  // in that case, i need to modify one saved ra
  // and then PIC works well
  asm volatile("addi t6, x0, 0x3f \n"
               "slli t6, t6, 32 \n"
               "add sp, sp, t6 \n"
               "add fp, fp, t6 \n"
               "add ra, ra, t6 \n");
  // change the saved ra & sp, if possible.
  uint64 *fp = (uint64 *)r_fp();
  *fp = *fp + KVMOFFSET;
  *(fp + 1) = *(fp + 1) + KVMOFFSET;
}

// fix the kmm linklist value by adding KVMOFFSET
// lockless because it's single core here.
void kmmfix() {
  kmem.freelist = (struct run *)((uint64)kmem.freelist + KVMOFFSET);
  struct run *r = kmem.freelist;
  while (r->next) {
    r->next = (struct run *)((uint64)r->next + KVMOFFSET);
    r = r->next;
  }
  printf("ok, ");
}

