/** @note 进程状态队列锁说明:
 *        进程状态队列处在高并发的环境，需要良好的锁控制
 *        全局锁顺序：状态队列的锁优先级高于进程锁（防止死锁）
 */

fproclist_t proc_freelist;
statelist_t proc_readylist;
statelist_t proc_sleeplist;
statelist_t proc_zombielist;

// map the kernel stack of each process
void proc_kstacks(pagetable_t kpgtbl) {
  struct proc *p;

  for (p = process; p < &process[NPROC]; p++) {
    char *pa = PgAlloc();
    if (pa == 0)
      panic("PgAlloc");
    uint64 va = KSTACK((int)(p - process));
    kvmmap(kpgtbl, va, (uint64)pa, PGSIZE, PTE_R | PTE_W);
  }
}

