  for (p = process; p < &process[NPROC]; p++) {
    if (p->pid == pid)
      return p;
  }
  //assert(p->pid == pid);
  return 0;
}

bool havekid(struct proc *p) {
  bool havekids = 0;
  struct proc *pp;
  for (pp = process; pp < &process[NPROC]; pp++) {
    acquire(&pp->lock);
    if (pp->parent == p) {
      havekids = 1;
    }
    release(&pp->lock);
    if (havekids)
      break;
  }
  return havekids;
}

void procinit() {
  struct proc *p;

  initlock(&proc_freelist.lock, "proc");
  initlock(&state_lock, "state_lock");

  TAILQ_INIT(&proc_freelist.list);
  TAILQ_INIT(&proc_readylist.list);
  TAILQ_INIT(&proc_zombielist.list);
  TAILQ_INIT(&proc_sleeplist.list);
  initlock(&proc_freelist.lock, "procfreelist");
  initlock(&proc_readylist.lock, "procreadylist");
  initlock(&proc_zombielist.lock, "proczombielist");
  initlock(&proc_sleeplist.lock, "procsleeplist");

  for (p = &process[NPROC - 1]; p >= process; p--) {
    int pseq = (int)(p - process);
    initlock(&p->lock, "proc");
    p->state = UNUSED;
    p->kstack = KSTACK(pseq);
    TAILQ_INIT(&p->umaphead);
    TAILQ_INIT(&p->sigqueue);
    TAILQ_INSERT_HEAD(&proc_freelist.list, p, node);
  }
  proc_freelist.nextpid = 1;

  sleepinit();
  MapInit();
  shm_init();
}
// alloc a proc. do not deal pgtbl
// 所做工作：分配pid、清零context。
// need to be switched status by other func
struct proc *procalloc() {
  struct proc *p = NULL;

  acquire(&proc_freelist.lock);
  p = TAILQ_FIRST(&proc_freelist.list);
  if (p == NULL) {
    release(&proc_freelist.lock);
    return NULL;
  }
  TAILQ_REMOVE(&proc_freelist.list, p, node);
  release(&proc_freelist.lock);

  p->pid = proc_freelist.nextpid;
  proc_freelist.nextpid++;
  if (p->state != UNUSED)
    panic("procalloc");

  memset(&p->ucontext, 0, sizeof(struct context));

  return p;
}

// free the proc exclusive pages
// must be called when p->state == ZOMBIE
void procfree(struct proc *p) {
  if (p->state != ZOMBIE)
    panic("procfree: what are you freeing about?");

  if (p->pagetable)
    proc_FreeUpt(p, p->pagetable, p->databrk, 1);
  p->pagetable = 0;
  p->state = UNUSED;
  p->databrk = 0;
  p->killed = 0;
  p->parent = 0;
  p->pid = 0;
  p->trapframe = (struct trapframe){0};

  assert(holding(&proc_zombielist.lock));
  TAILQ_REMOVE(&proc_zombielist.list, p, node);

  acquire(&proc_freelist.lock);
  TAILQ_INSERT_TAIL(&proc_freelist.list, p, node);
  release(&proc_freelist.lock);
}

void procrun(struct proc *p) {
  assert(p->state == UNUSED || p->state == SLEEPING);
  p->state = RUNNABLE;
  acquire(&proc_readylist.lock);
  TAILQ_INSERT_HEAD(&proc_readylist.list, p, node);
  release(&proc_readylist.lock);
}

void trapframe_clear(struct proc *p) {
  // t0 - s1
  memset((void *)&p->trapframe + 72, 0, 112 - 72);
  // a3 - t6
  memset((void *)&p->trapframe + 136, 0, 288 - 136);
}

