// scheduler func only be called in kernel mode
// wont be called in user pgtbl
// the kernel mode only runs in scheduler or intr handler.
void scheduler() {
  struct proc *p;
  struct cpu *c = getcpu();

  c->process = 0;

  /** @note proc_readylist是一个队列，循环获取队列头作为选择的进程,
   *        并将新待调度进程加到队列尾，为FIFO。
   */
  for (;;) {
    intr_on();
    __sync_synchronize();
    acquire(&proc_readylist.lock);
    p = TAILQ_FIRST(&proc_readylist.list);
    if (p == NULL) {
      release(&proc_readylist.lock);
      continue;
    }
    TAILQ_REMOVE(&proc_readylist.list, p, node);

    //交替锁顺序，防止此时触发中断。此过程无死锁风险。
    acquire(&p->lock);
    release(&proc_readylist.lock);

    assert(p->state == RUNNABLE);
    p->state = RUNNING;
    c->process = p;
    //此处表示进程被切入
    swtch(&c->kcontext, &p->ucontext, MAKE_SATP((uint64)kern_pagetable));
    //此处表示进程被切出，检查是否是RUNNABLE or SLEEPING
    c->process = 0;
    // SLEEPING 不会加入就绪队列。会等待wakeup将其加入就绪队列。
    // ZOMBIE 则由wait将其加入空闲队列。在进入scheduler前即加入僵尸队列。
    assert(p->state == RUNNABLE || p->state == SLEEPING || p->state == ZOMBIE);
    if (p->state == RUNNABLE) {
      acquire(&proc_readylist.lock);
      TAILQ_INSERT_TAIL(&proc_readylist.list, p, node);
      release(&p->lock);
      release(&proc_readylist.lock);
    }
    //睡眠进程要等到切换页表后才释放sleeplist锁，防止lost wakeup
    else if (p->state == SLEEPING) {
      release(&p->lock);
      release(&proc_sleeplist.lock);
    } else
      release(&p->lock);
  }
}

// 锁问题太多，重新引用xv6切换上下文检查
void CheckAndSwtch(uint64 pagetable_PA) {
  int intena;
  struct proc *p = getproc();
  struct cpu* cpu = getcpu();

  if (!holding(&p->lock))
    panic("sched p->lock");
  if (p->state != SLEEPING && cpu ->noff != 1)
    panic("sched locks");
  if (p->state == SLEEPING && cpu ->noff != 2)
    panic("no sleeplist locks");
  if (p->state == RUNNING)
    panic("sched running");
  if (intr_get())
    panic("sched interruptible");

  intena = getcpu()->intena;
  swtch(&p->ucontext, &getcpu()->kcontext, MAKE_SATP(pagetable_PA));
  getcpu()->intena = intena;
}

