#define MAX_AT 14
#define ADD_AUXVECTOR(id, val)                                                      \
  aux[auxindex++] = id;                                                        \
  aux[auxindex++] = val;

static int pushstack(struct elfhdr *elf, pagetable_t newupt, char **argv,
                     char **envp, uint64 vaseg, uint64 base, uint64 entry) {
  uint64 sp = USTACKBASE - PGSIZE;
  uint64 stackstop = USTACKSTOP;
  uint64 uargv[MAXARG];
  uint64 uenvp[MAXARG];
  int argc = 0, envc = 0;
  struct proc *p = getproc();
  char *temp;

  sp -= 2 * sizeof(uint64);

  uint64 aux[MAX_AT * 2];
  int auxindex = 0;
  memset(aux, 0, sizeof(aux));

  if (argv) {
    for (argc = 0; argv[argc]; argc++) {
      temp = argv[argc];
      if (argc >= MAXARG)
        return -1;
      sp -= strlen(temp) + 1;
      sp -= sp % 16;        // riscv sp must be 16-byte aligned
      if (sp < stackstop)
        return -1;
      if (copyout(newupt, (void *)sp, argv[argc], strlen(argv[argc]) + 1) < 0)
        return -1;
      uargv[argc] = sp;
    }
  }
  uargv[argc] = 0;

  if (envp) {
    for (envc = 0; envp[envc] && envc < 0; envc++) {
      temp = envp[envc];
      if (envc >= MAXARG)
        return -1;
      sp -= strlen(temp) + 1;
      sp -= sp % 16;        // riscv sp must be 16-byte aligned
      if (sp < stackstop)
        return -1;
      if (copyout(newupt, (void *)sp, envp[envc], strlen(envp[envc]) + 1) < 0)
        return -1;
      uenvp[envc] = sp;
    }
  }
  uenvp[envc] = 0;

  sp -= 16;
  uint64_t random[2] = {0xbd5c2042d3d5b461, 0x46b568c6ae612cc0};
  if (sp < stackstop || copyout(newupt, (void *)sp, (void *)random, 16) < 0)
    return -1;

  ADD_AUXVECTOR(AT_HWCAP, 0);
  ADD_AUXVECTOR(AT_PAGESZ, PGSIZE);
  ADD_AUXVECTOR(AT_PHDR, vaseg);
  ADD_AUXVECTOR(AT_PHENT, elf->phentsize);
  ADD_AUXVECTOR(AT_PHNUM, elf->phnum);
  ADD_AUXVECTOR(AT_BASE, base);
  ADD_AUXVECTOR(AT_ENTRY, elf->entry);
  ADD_AUXVECTOR(AT_UID, 0);
  ADD_AUXVECTOR(AT_EUID, 0);
  ADD_AUXVECTOR(AT_GID, 0);
  ADD_AUXVECTOR(AT_EGID, 0);
  ADD_AUXVECTOR(AT_SECURE, 0);
  ADD_AUXVECTOR(AT_RANDOM, sp);
  ADD_AUXVECTOR(AT_NULL, 0);

  sp -= sizeof(aux);
  if (copyout(newupt, (void *)sp, (void *)aux, sizeof(aux)) < 0)
    return -1;

  if (envc) {
    sp -= (envc + 1) * sizeof(uint64);
    sp -= sp % 16;
    if (copyout(newupt, (void *)sp, (void *)uenvp,
                (envc + 1) * sizeof(uint64)) < 0)
      return -1;
    p->trapframe.a2 = sp;
  }

  if (argc) {
    sp -= (argc + 1) * sizeof(uint64);
    sp -= sp % 16;
    if (copyout(newupt, (void *)sp, (void *)uargv,
                (argc + 1) * sizeof(uint64)) < 0)
      return -1;
    p->trapframe.a1 = sp;

    sp -= sizeof(uint64);
    uint64 argcc = argc;
    if (copyout(newupt, (void *)sp, (void *)&argcc, sizeof(uint64)) < 0)
      return -1;


    //printf("pushstack: sp: %p, a1: %p, a2: %p, argc: %d, envc: %d\n",sp,p->trapframe.a1,p->trapframe.a2,argc,envc);
  }

  p->trapframe.sp = sp;
  return argc;
}

static int loadseg(pagetable_t pagetable, uint64 va, void *file, uint64 offset,
                   uint64 sz) {
  uint64 i, n;
  uint64 oa;
  uint64 pageoff;
  for (i = 0; i < sz;) {
    pageoff = (va + i) % PGSIZE;
    // 获取页表中的物理地址起始地址
    oa = PtGetAddr(pagetable, va + i - pageoff);
    if (oa == 0)
      panic("loadseg: address should exist");

    // 计算实际要读取的字节数
    if (sz - i < PGSIZE - pageoff)
      n = sz - i;
    else
      n = PGSIZE - pageoff;

    // 从文件中读取数据到物理地址的正确位置
    if (general_fileread(file, oa + pageoff, offset + i, n) != n)
      return -1;

    // 更新偏移量i
    i += n;
  }

  return 0;
}

static int flags2perm(int flags) {
  int perm = 0;
  if (flags & 0x1)
    perm = PTE_X;
  if (flags & 0x2)
    perm |= PTE_W;
  return perm;
}

