    if (p->killed == 1)
      exit(-1);
    p->trapframe.epc += 4;
    // intr_on();
    syscall_entry();
    stime_end(p);
  }  // 缺页
  else if (cause == 13 || cause == 15) {
    pagefault_handler(cause);
  }  // 中断
  else if ((which_dev = devintr()) != 0) {
    // ok
    // 其他异常，报错并杀死进程
  } else {
    printf("usertrap(): unexpected scause %p pid=%d\n", r_scause(), p->pid);
    printf("            sepc=%p stval=%p\n", r_sepc(), r_stval());
    p->killed = 1;
  }
  if (p->killed == 1)
    exit(-1);
  // give up the CPU if this is a timer interrupt.
  if (which_dev == 2)
    yield();
  usertrapret();
}

void usertrapret() {
  struct proc *p = getproc();
  SigCheck();
  intr_off();
  utime_start(p);
  // send syscalls, interrupts, and exceptions to uservec in trampoline.S
  w_stvec((uint64)uservec);

  // set up trapframe values that uservec will need when
  // the process next traps into the kernel.
  p->trapframe.kernel_sp = p->kstack + PGSIZE;        // process's kernel stack
  p->trapframe.kernel_trap = (uint64)usertrap;
  p->trapframe.kernel_hartid = r_tp();        // hartid for cpuid()

  // set up the registers that trampoline.S's sret will use
  // to get to user space.

  // set S Previous Privilege mode to User.
  unsigned long x = r_sstatus();
  x &= ~SSTATUS_SPP;        // clear SPP to 0 for user mode
  x |= SSTATUS_SPIE;        // enable interrupts in user mode
  w_sstatus(x);

  // set S Exception Program Counter to the saved user pc.
  w_sepc(p->trapframe.epc);

  // jump to userret in trampoline.S at the top of memory, which
  // switches to the user page table, restores user registers,
  // and switches to user mode with sret.
  uint64 sscratch = (uint64)(&p->trapframe);
  ((void (*)(uint64))(userret))(sscratch);
}

void kerneltrap() {
  int which_dev = 0;
  uint64 sepc = r_sepc();
  uint64 sstatus = r_sstatus();
  uint64 scause = r_scause();

  if ((sstatus & SSTATUS_SPP) == 0)
    panic("kerneltrap: not from supervisor mode");
  if (intr_get() != 0)
    panic("kerneltrap: interrupts enabled");

  if ((which_dev = devintr()) == 0) {
    printf("scause %p\n", scause);
    printf("sepc=%p stval=%p\n", sepc, r_stval());
    panic("kerneltrap");
  }

  // give up the CPU if this is a timer interrupt.
  // is it need to yield? seems not.
  if (which_dev == 2)
    trap_timer();

  w_sepc(sepc);
  w_sstatus(sstatus);
}

void trap_timer() {
  handler_timer_int();
  secheck();
}

static void pagefault_handler(int cause){
  struct proc* p = getproc();
  //检查lazy alloc与COW与mmap
  uint64 fault_va = r_stval();
  fcause = cause;
  fsepc = r_sepc();
  // 是否在数据段上
  if (fault_va < p->databrk + UVMBASE && fault_va >= UVMBASE) {
    // 检查是否数据段COW引起
    if (fault_va != 0 && CowCheck(p->pagetable, fault_va) == 1) {
      CowAlloc(p->pagetable, PGROUNDDOWN(fault_va));
    } else {
      // 检查是否已经有物理页分配，如有则代表是没有页权限。
      // 没有，则代表数据段brk懒分配引起
      // 0地址的缺页直接认为SIGSEGV

      // for debug.
      fpte = PtWalk(p->pagetable, fault_va, 0);
      if (fpte)
        fflag = PTE_FLAGS(*fpte);
      uint64 paddr = PtGetAddr(p->pagetable, fault_va);

      if (fault_va == 0 || paddr) {
        printf("usertrap(): scause %p pid=%d\n", r_scause(), p->pid);
        printf("            sepc=%p stval=%p\n", r_sepc(), r_stval());
        printf("killing process pid: %d\n", p->pid);
        SigSend(p, SIGSEGV);
      } else {
        uint64 oa = (uint64)PgAlloc();
        PtMapPage(p->pagetable, PGROUNDDOWN(fault_va), oa,
                  PTE_U | PTE_W | PTE_R);
      }
    }
  } //检查是否是栈COW引起
  else if (cause == 15 && fault_va >= USTACKSTOP &&
             CowCheck(p->pagetable, fault_va) == 1) {
    CowAlloc(p->pagetable, PGROUNDDOWN(fault_va));
  } //检查是否是mapregion懒分配引起
  else if (fault_va >= UMAPBASE && fault_va < UMAPSTOP) {
    //uint64* fpte = PtWalk(p->pagetable, fault_va, 0);
    //printf("%p\n",fpte);
    int ret = mmaprw(fault_va, r_scause());
    if (ret == ERR)
      SigSend(p, SIGSEGV);
  }
  //检查失败，发送SIGSEGV段错误信号
  else {
    printf("usertrap(): scause %p pid=%d\n", r_scause(), p->pid);
    printf("            sepc=%p stval=%p\n", r_sepc(), r_stval());
    printf("process pid sigsegv : %d\n", p->pid);
    SigSend(p, SIGSEGV);
  }
}

