// interupt.c, handles interupt from kernpage
// if proc need to be switched, then it will change to kpgtbl by kernpagevec.S

// funcs:
// yield       --  calls swtch.S, which change to kernel mode
// devintr     --  dev intr handler

extern pagetable_t kern_pagetable;

int devintr() {
  uint64 scause = r_scause();

  if ((scause & 0x8000000000000000L) && (scause & 0xff) == 9) {

    int irq = plic_claim();
    if (irq == UART0_IRQ) {
      int c = SBI_GETCHAR();
      if (-1 != c) {
        panic("uart?");
        // consoleintr(c);
      }
    } else if (irq == VIRTIO0_IRQ) {
      virtio_disk_intr();
    } else if (irq) {
      printf("unexpected interrupt irq=%d\n", irq);
    }
    if (irq)
      plic_complete(irq);
    return 1;
  } else if (0x8000000000000005L == scause) {
    trap_timer();
    return 2;
  } else {
    return 0;
  }
}

void yield() {
  struct proc *p = getproc();
  acquire(&p->lock);
  p->state = RUNNABLE;
  // change pagetable here
  CheckAndSwtch((uint64)p->pagetable - KVMOFFSET);

  release(&p->lock);
}

