// SYSCALL函数，允许直接解引用用户指针，用户的buf可以直接使用。

void syscall_entry() {
  struct proc *p = getproc();
  uint64 sysno = p->trapframe.a7;
  if (sysno > 0 && sysno < MAXSYSNO && syscalls[sysno] != NULL) {
     //printf("pid : %d called syscall : %d\n",p->pid,sysno);

    /** @bug 由于未知（可能是并发）bug，如果不加入一段延时，在busybox测试
     *       中即会导致进程访问无效地址而退出，而加入一段延时则表面上解决了此问题。
     * 
     *  经排查是fork的问题,但还不知道成因（断点调试会造成延时，使之无法复现问题）
     */
    //for (int i = 0; i < 4000000; i++) ;

    uint64 syscall_addr = (uint64)syscalls[sysno] + KVMOFFSET;
    assert(syscall_addr < KVMOFFSET * 2);
    uint64 (*syscall_func)(void) = (uint64(*)(void))syscall_addr;
    uint64 ret = syscall_func();
    p->trapframe.a0 = ret;
  } else {
    printf("%d: unknown sys call %d\n", p->pid, sysno);
    p->trapframe.a0 = -1;
  }
}

uint64 argraw(int n) {
  struct proc *p = getproc();
  if (n > 5 || n < 0)
    panic("argraw");
  uint64 *ret = &p->trapframe.a0;
  return *(ret + n);
}

int checkarg(uint64 addrArg) {
  if (addrArg == 0)
    return 1;
  struct proc *p = getproc();
  pte_t *pte;
  if ((pte = PtWalk(p->pagetable, addrArg, 0)) == NULL)
    return 0;
  if ((*pte & PTE_R) == 0 || (*pte & PTE_U) == 0)
    return 0;
  return 1;
}

