uint64 sys_execve() {
  char *path = (char *)argraw(0);
  char **argv = (char **)argraw(1);
  char **envp = (char **)argraw(2);

  if (!checkarg((uint64)path) || !checkarg((uint64)argv) ||
      !checkarg((uint64)envp))
    return -EINVAL;
  int ret = exec(path, argv, envp);
  struct proc *p = getproc();
  p->ctid = 0;
  return ret;
}
