int _sys_prlimit64(uint32 pid, int resource, uint64 pnew_limit,
                   uint64 pold_limit) {
  struct proc *p = getproc();
  if (pold_limit != 0) {
    struct rlimit oldlimit;
    switch (resource) {
    case RLIMIT_NOFILE:
      oldlimit.rlim_cur = p->rlimit_files_cur;
      oldlimit.rlim_max = p->rlimit_files_max;
      break;
    case RLIMIT_STACK:
      oldlimit.rlim_cur = oldlimit.rlim_max = USTACKSIZE;
      break;
    default:
      return -EINVAL;
    }
    copyout(p->pagetable, (void *)pold_limit, &oldlimit, sizeof(oldlimit));
  }

  if (pnew_limit != 0) {
    struct rlimit newlimit;
    memmove(&newlimit, (void *)pnew_limit, sizeof(newlimit));
    if (newlimit.rlim_cur > newlimit.rlim_max) {
      return -EINVAL;
    }
    switch (resource) {
    case RLIMIT_NOFILE:
      if (newlimit.rlim_max > 128) {
        return -EINVAL;
      }
      p->rlimit_files_cur = newlimit.rlim_cur;
      p->rlimit_files_max = newlimit.rlim_max;
      break;
    default:
      return 0;
    }
  }
  return 0;
}

uint64 sys_prlimit64() {
  uint32 pid = (uint32)argraw(0);
  int resource = (int)argraw(1);
  uint64 pnew_limit = argraw(2);
  uint64 pold_limit = argraw(3);
  int ret = _sys_prlimit64(pid, resource, pnew_limit, pold_limit);
  return ret;
}

