void ProcSigReset(struct proc *p) {
  p->sighandling = NULL;
  p->sigmask = (struct sigset){0};
  p->itimer = 0;
  sigevent_t *pse;
  sigevent_t *prevse = NULL;
  TAILQ_FOREACH(pse, &p->sigqueue, node) {
    if (prevse) {
      SigEventFree(prevse);
      TAILQ_REMOVE(&p->sigqueue, prevse, node);
    }
    prevse = pse;
  }
  if (prevse) {
    SigEventFree(prevse);
    TAILQ_REMOVE(&p->sigqueue, prevse, node);
  }
  TAILQ_INIT(&p->sigqueue);
}

void SigSend(struct proc *p, int signum) {
  acquire(&p->lock);
  sigevent_t *se = SigEventAlloc(signum);
  TAILQ_INSERT_HEAD(&p->sigqueue, se, node);
  release(&p->lock);

  if (signum == SIGKILL) {
    p->killed = 1;
    wakeup(p);
  }
}

static void SigHandlerStart(struct proc *p, sigevent_t *se, sigaction_t *sa) {
  se->se_status = SE_PROCESSING;
  se->se_restoretf = p->trapframe;
  se->se_restoremask = p->sigmask;
  if (p->sighandling)
    se->lastprocessing = p->sighandling;
  p->sighandling = se;

  // sigset_t newsigset;
  int len = sizeof(p->sigmask.ss_byte);
  for (int i = 0; i < len; i++) {
    p->sigmask.ss_byte[i] |= sa->sa_mask.ss_byte[i];
  }
  p->trapframe.sp -= (0x1000 + sizeof(uint64));
  p->trapframe.ra =
      sa->sa_restorer ? (uint64)sa->sa_restorer : SIGNAL_TRAMPOLINE;
  p->trapframe.epc = (uint64)sa->sa_handler;
  p->trapframe.a0 = se->se_signo;
  if (sa->sa_flags & SA_SIGINFO) {
    panic("siginfo: unfinished");
  }
}

static void SigHandlerFini(struct proc *p, sigevent_t *se) {
  p->trapframe = se->se_restoretf;
  p->sigmask = se->se_restoremask;
  p->sighandling = se->lastprocessing;
}

static void SigHandlerDefault(struct proc *p, sigevent_t *se) {
  if (se->se_signo == SIGKILL || se->se_signo == SIGTERM ||
      se->se_signo == SIGSEGV) {
    p->killed = 1;
    release(&p->lock);
    exit(-1);
  }
}

/**  @note 逻辑：在中断结束时（防止与syscall冲突）检查信号，
 *         进入一个新的中断信号处理流程。在流程进行中不允许处理信号。
 */
void SigCheck() {
  struct proc *p = getproc();
  if (p->killed)
    return;

  acquire(&p->lock);
  while (1) {
    sigevent_t *se = SigEventFetch(p);
    if (se == NULL) {
      break;
    }
    sigaction_t *sa = SigActGet(p, se->se_signo);
    if (sa->sa_handler == NULL) {
      SigHandlerDefault(p, se);
      // may no return
      TAILQ_REMOVE(&p->sigqueue, se, node);
      SigEventFree(se);
    } else {
      SigHandlerStart(p, se, sa);
      TAILQ_REMOVE(&p->sigqueue, se, node);
      release(&p->lock);
      return;
    }
  }
  release(&p->lock);
}

void SigRet() {
  struct proc *p = getproc();
  sigevent_t *se = p->sighandling;
  SigHandlerFini(p, se);
  acquire(&p->lock);
  TAILQ_REMOVE(&p->sigqueue, se, node);
  release(&p->lock);
  SigEventFree(se);
}

bool isSigMasked(struct proc *p, int signo) {
  assert(signo > 0 && signo < SIGNAL_MAX);
  // acquire(&p->lock);
  signo = signo - 1;
  bool ret = p->sigmask.ss_byte[signo / 8] & (1 << (signo % 8));
  // release(&p->lock);
  return ret;
}

void sig_timedwait(sigset_t *set, siginfo_t *info, uint64 timeout) {
  if (timeout != 0) {
    sesleep("#sigwait", 0, timeout + time_mono_us());
  }
  sigevent_t *se = SigEventFetch(getproc());
  if (se != NULL) {
    info->si_signo = se->se_signo;
  }
}

