void fs_clearproc(struct proc *p) {
  for (int i = 0; i < NUSERFD; i++) {
    if (p->userfd[i] != -1) {
      int kfd = p->userfd[i];
      if (kfd > 2)
        fdclose(i);
    }
  }
  void *cwd = p->cwd;
  if (cwd != 0)
    general_fileclose(cwd);
  p->cwd = 0;
}

