int fd_file_read(struct fd *fd, uint64 dst, uint64 off, uint64 n) {
  int ret;
#ifdef FSTYPE_FAT32
  struct dirent *dir = fd->dirent;
  if (dir == NULL || dir->type == DIR_DIR)
    return ERR;
  ret = fileread(dir, dst, off, n);
#endif
#ifdef FSTYPE_EXT4
  struct ext4_file *file = fd->ext_file;
  if (file == NULL)
    return -EBADF;
  ret = ext_FileRead(file, (void *)dst, n);
#endif
  return ret;
}

int fd_file_write(struct fd *fd, uint64 src, uint64 off, uint64 n) {
  int ret;
#ifdef FSTYPE_FAT32
  struct dirent *dir = fd->dirent;
  if (dir == NULL || dir->type == DIR_DIR)
    return ERR;
  ret = fileread(dir, dst, off, n);
#endif
#ifdef FSTYPE_EXT4
  struct ext4_file *file = fd->ext_file;
  if (file == NULL)
    return -EBADF;
  ret = ext_FileWrite(file, (void *)src, n);
#endif
  return ret;
}

void fdinit() {
  initlock(&fdfreelist.lock, "fdfreelist");
  initlock(&getdent64buf.lock, "getdent64");
  console_fd_alloc();
}

void procfdinit(struct proc *p) {
  for (int i = 0; i < NUSERFD; i++) {
    p->userfd[i] = -1;
  }
  p->userfd[0] = stdinfd;
  p->userfd[1] = stdoutfd;
  p->userfd[2] = stderrfd;
  kernfd[stdinfd].refcnt = 1;
  kernfd[stdoutfd].refcnt = 1;
  kernfd[stderrfd].refcnt = 1;
}

// alloc a free kernfd.
// return -1 if not available
int fdalloc() {
  acquire(&fdfreelist.lock);
  int i;
  for (i = 0; i < NKERNFD; i++) {
    int index = i / 8;
    int bit = i % 8;
    if ((fdfreelist.bitmap[index] & (1 << bit)) == 0) {
      fdfreelist.bitmap[index] |= 1 << bit;
      memset(&kernfd[i], 0, sizeof(struct fd));
      kernfd[i].refcnt = 1;
      initsleeplock(&kernfd[i].fdlock, "fdlock");
      break;
    }
  }
  release(&fdfreelist.lock);
  if (i >= NKERNFD)
    return -1;
  else
    return i;
}
// refcnt--; uses kfd
// when refcnt is zero, relse a kernfd
// do not overwrite the fd content
void fdrelse(int kfd) {
  //不处理consolefd
  if (kfd < 2)
    return;
  struct fd *fdi = &kernfd[kfd];
  fdrefcnt(kfd, -1);
  //不存在refcnt为0后又增加1的临界区。这在功能上不可能，所以可以无锁检查。
  if (fdi->refcnt == 0) {
    int index = kfd / 8;
    int bit = kfd % 8;
    acquire(&fdfreelist.lock);
    fdfreelist.bitmap[index] &= ~(1 << bit);
    if (fdi->type == Dev_File) {
#ifdef FSTYPE_FAT32
      struct dirent *dir = fdi->dirent;
      fileclose(dir);
#endif
#ifdef FSTYPE_EXT4
      ext_FileClose(fdi->ext_file);
      fdi->ext_file = NULL;
#endif
    } else if (fdi->type == Dev_Pipe)
      pipeclose(fdi);
    release(&fdfreelist.lock);
  }
}

void fdrefcnt(int kfd, int perm) {
  if (kfd <= 2)
    return;
  struct fd *fdi = &kernfd[kfd];
  __sync_fetch_and_add(&fdi->refcnt, perm);
}

// -1表示未使用，-2表示正在分配中。数值可以改为define宏定义。
// 有可能有-2分配未回收的bug，因此kfd做检查也仍是必要的。
int ufdalloc(struct proc *p) {
  int ret = -1;
  for (int i = 0; i < NUSERFD; i++) {
    if(i > p->rlimit_files_max - 1)
      return -1;
    if (p->userfd[i] == -1) {
      p->userfd[i] = -2;
      ret = i;
      break;
    }
  }
  return ret;
}

inline struct dirent *getcwd() {
  struct proc *p = getproc();
  return p->cwd;
}

// close a userfd.
// will call fdrelse to operate kernfd refcnt.
// TODO: close func behaviors differ from each fdtype.
int fdclose(int ufd) {
  struct proc *p = getproc();
  int kfd = p->userfd[ufd];
  p->userfd[ufd] = -1;
  if (kfd < 0 || kfd > NKERNFD)
    return ERR;
  fdrelse(kfd);
  return 0;
}

static bool isReadable(int ufd) {
  struct proc *p = getproc();
  int kfd = p->userfd[ufd];
  if (kfd < 0 || kfd > NKERNFD)
    return 0;
  struct fd *kfdi = &kernfd[kfd];
  int ret;
  if (kfdi == NULL) {
    return -EBADF;
  }
  acquiresleep(&kfdi->fdlock);

  if (kfdi->type == Dev_Pipe) {
    ret = pipe_check_read(kfdi->pipe);
  } else if (kfdi->type == Dev_Console) {
    ret = console_check_read();
  } else {
    ret = 1;
  }

  releasesleep(&kfdi->fdlock);
  return ret;
}

static bool isWritable(int ufd) {
  struct proc *p = getproc();
  int kfd = p->userfd[ufd];
  if (kfd < 0 || kfd > NKERNFD)
    return 0;
  struct fd *kfdi = &kernfd[kfd];
  int ret;
  if (kfdi == NULL) {
    return -EBADF;
  }
  acquiresleep(&kfdi->fdlock);

  if (kfdi->type == Dev_Pipe) {
    ret = pipe_check_write(kfdi->pipe);
  } else if (kfdi->type == Dev_Console) {
    ret = console_check_write();
  } else {
    ret = 1;
  }

  releasesleep(&kfdi->fdlock);
  return ret;
}

void* general_FdToFile(int ufd){
  void* file;
  struct proc *p = getproc();
  int kfd = p->userfd[ufd];
  if (kfd < 0 || kfd > NKERNFD)
    return 0;
  struct fd *kfdi = &kernfd[kfd];
#ifdef FSTYPE_FAT32
  file = kfdi->dirent;
#endif
#ifdef FSTYPE_EXT4
  file = kfdi->ext_file;
#endif
  return file;
}

static char *ext_GetBaseFdFile(int ufd) {
  struct proc *p = getproc();

  char *ret;
  if (ufd == AT_FWCWD) {
    ret = p->cwdpath;
  } else {
    if (ufd < 0 || ufd >= NUSERFD)
      return 0;
    int kdirfd = p->userfd[ufd];
    if (kdirfd < 0 || kdirfd >= NKERNFD)
      return 0;
    struct fd *kdirfdi = &kernfd[kdirfd];
    if (kdirfdi->type != Dev_File)
      return 0;
    ret = kdirfdi->name;
  }
  return ret;
}

// dup a user fd to a smallest unused userfd
// return -1 if not success
// return newfd if success
int dup(int fd) {
  struct proc *p = getproc();
  int kfd = p->userfd[fd];
  if (kfd < 0 || kfd > NKERNFD) {
    return -1;
  }
  int ufd = ufdalloc(p);
  if(ufd < 0)
    return -EMFILE;
  p->userfd[ufd] = kfd;
  fdrefcnt(kfd, 1);
  return ufd;
}

int dup3(int oldfd, int newfd) {
  if (newfd == oldfd)
    return -1;
  struct proc *p = getproc();
  int kfd = p->userfd[oldfd];
  if (kfd < 0 || kfd > NKERNFD) {
    return -1;
  }
  int newkfd = p->userfd[newfd];
  if (newkfd != -1 && newkfd < NKERNFD) {
    fdclose(newfd);
  }
  fdrefcnt(kfd, 1);
  p->userfd[newfd] = kfd;
  return newfd;
}

int ppoll(uint64 fds, int nfds, uint64 tmo_p, uint64 sigmask) {
  struct pollfd poll_fd;
  // struct timespec tmo;
  int ret = 0;
  struct proc *p = getproc();

  while (1) {
    ret = 0;
    for (int i = 0; i < nfds; i++) {
      uint64 cur_fds = fds + i * sizeof(poll_fd);
      memcpy(&poll_fd, (void *)cur_fds, sizeof(poll_fd));
      poll_fd.revents = 0;

      if (poll_fd.fd < 0) {
        poll_fd.revents = 0;
      } else {
        if (poll_fd.events & POLLIN) {
          int r = isReadable(poll_fd.fd);
          if (r < 0) {
            if (r == -1)
              poll_fd.revents |= POLLHUP;
            else
              return r;
          }
          if (r)
            poll_fd.revents |= POLLIN;
        }
        if (poll_fd.events & POLLOUT) {
          int r = isWritable(poll_fd.fd);
          if (r < 0)
            return r;
          if (r)
            poll_fd.revents |= POLLOUT;
        }
      }
      copyout(p->pagetable, (void *)cur_fds, &poll_fd, sizeof(poll_fd));
      if (poll_fd.revents != 0)
        ret += 1;
    }
    if (ret || tmo_p)
      break;
  }
  return ret;
}

