char *ext4_GetStrFlags(int flags) {
  char *ret = NULL;

  if (flags == O_RDONLY) {
    ret = "r";
    return ret;
  }
  // if(flags & O_WRONLY && !(flags & O_RDONLY)){
  //   ret = "a";
  // }
  if (flags & O_WRONLY && flags & O_CREAT && flags & O_TRUNC) {
    ret = "w";
    return ret;
  }
  if (flags & O_WRONLY && flags & O_CREAT && flags & O_APPEND) {
    ret = "a";
    return ret;
  }
  if (flags & O_RDWR && flags & O_CREAT && flags & O_TRUNC) {
    ret = "w+";
    return ret;
  }
  if (flags & O_RDWR && flags & O_CREAT && flags & O_APPEND) {
    ret = "a+";
    return ret;
  }
  if (flags & O_RDWR && flags & O_CREAT) {
    ret = "a+";
    return ret;
  }
  if (flags & O_RDWR) {
    ret = "r+";
    return ret;
  }
  return "r";
}

