int ext_FileRead(struct ext4_file *file, void *buf, size_t count) {
  size_t bytesread = 0;
  int r;

  assert(file != NULL);
  r = ext4_fread(file, buf, count, &bytesread);
  if (r != 0)
    bytesread = 0;
  return bytesread;
}

int ext_FileWrite(struct ext4_file *file, const void *buf, size_t count) {
  size_t byteswritten = 0;
  int r;

  assert(file != NULL);
  r = ext4_fwrite(file, buf, count, &byteswritten);
  if (r != 0)
    byteswritten = 0;
  return byteswritten;
}

int64 ext_FileLseek(struct ext4_file *file, off_t offset, int whence) {
  int64 r;
  if(whence == SEEK_SET && offset > file->fsize)
    file->fsize = offset;
  r = ext4_fseek(file, (int64_t)offset, whence);
  if (r == EOK)
    return file->fpos;
  return -r;
}

