//有可能打开的是ext4_dir。如果是，仍将其看待为ext4_file.
struct ext4_file *ext_Open(char *filename, char *flags, mode_t mode) {
  ext4_file *newfile = kmalloc(ext4_buddy, sizeof(struct ext4_dir));
  int ret = ext4_fopen(newfile, (const char *)filename, flags);
  // mode unused.
  if (ret != EOK) {
    kfree(ext4_buddy, newfile);
    if (flags == NULL || !(flags[0] == 'r' && flags[1] == '\0'))
      return (void *)(uint64)ret;
    ext4_dir *newdir = kmalloc(ext4_buddy, sizeof(struct ext4_dir));
    int ret = ext4_dir_open(newdir, (const char *)filename);
    if (ret != EOK) {
      kfree(ext4_buddy, newdir);
      return (void *)(uint64)ret;
    } else
      return &newdir->f;
  }
  return newfile;
}

