int ext_Fstat(struct ext4_file* file, char *buf, char* path) {
  struct kstat pKStat;
  memset(&pKStat, 0, sizeof(struct kstat));
  struct ext4_mount_stats mps;
  mode_t mode = 511;

  struct ext4_dir *dir = (struct ext4_dir *)file;
  if (dir->de.inode != 0 || file->inode == 2)
    mode |= __S_IFDIR;
  else
    mode |= __S_IFREG;
  mode |= __S_IFCHR;
  if(!file->mp)
    return -EINVAL;
  ext4_mount_point_stats(file->mp->name, &mps);

  pKStat.st_dev = 0;
  pKStat.st_ino = file->inode;
  pKStat.st_mode = mode;
  pKStat.st_nlink = 1;
  pKStat.st_uid = 0;
  pKStat.st_gid = 0;
  pKStat.st_rdev = 0;
  pKStat.st_size = file->fsize;
  pKStat.st_blksize = mps.block_size;
  pKStat.st_blocks = ext4_ftell(file);
  uint32 time = 0;
  if(path != 0){
    ext4_atime_get(path,&time);
    pKStat.st_atime_nsec = time;
    ext4_ctime_get(path,&time);
    pKStat.st_ctime_nsec = time;
    ext4_mtime_get(path,&time);
    pKStat.st_mtime_nsec = time;
  }
  copyout(getproc()->pagetable, buf, &pKStat, sizeof(pKStat));
  return 0;
}

int ext_Faccess(const char *path, mode_t mode) {
  mode_t filemode;
  int ret = ext4_mode_get(path, &filemode);
  if (ret != 0)
    return -ret;
  // 没有用户概念，判断mode无意义。检查文件存在则返回成功即可。
  return 0;
}

int ext_Frename(char *oldpath, char *newpath) {
  int ret = ext4_frename(oldpath, newpath);
  if (ret != 0)
    return -ret;
  return 0;
}

