struct Dev pipeDev = {
    .dev_id = 'p',
    .dev_name = "pipe",
    .dev_read = piperead,
    .dev_write = pipewrite,
};

struct {
  struct pipe pipelist[64];
  struct spinlock lock;
  int cnt;
} kernpipe;

extern struct fd kernfd[NKERNFD];

void pipeinit() { initlock(&kernpipe.lock, "kernpipe"); }

int pipe(int fd[2]) {
  struct proc *p = getproc();
  int fd1, fd2, kfd1, kfd2;
  fd1 = ufdalloc(p);
  fd2 = ufdalloc(p);
  if (fd1 < 0 || fd2 < 0)
    return -EMFILE;
  kfd1 = fdalloc();
  kfd2 = fdalloc();
  if (kfd1 < 0 || kfd2 < 0) {
    fdrelse(kfd1);
    fdrelse(kfd2);
    fdclose(fd1);
    fdclose(fd2);
    return ERR;
  }
  fd[0] = fd1;
  fd[1] = fd2;

  struct fd *kfdi1 = &kernfd[kfd1];
  struct fd *kfdi2 = &kernfd[kfd2];
  struct pipe *pi = pipealloc(kfd1, kfd2);
  p->userfd[fd1] = kfd1;
  p->userfd[fd2] = kfd2;
  kfdi1->type = Dev_Pipe;
  kfdi1->flags = FS_RDONLY;
  kfdi1->offset = 0;
  kfdi1->dirent = NULL;
  kfdi1->ext_file = NULL;
  kfdi1->fdDev = &pipeDev;
  kfdi1->pipe = pi;

  kfdi2->type = Dev_Pipe;
  kfdi2->flags = FS_WRONLY;
  kfdi2->offset = 0;
  kfdi2->dirent = NULL;
  kfdi2->ext_file = NULL;
  kfdi2->fdDev = &pipeDev;
  kfdi2->pipe = pi;
  return 0;
}

struct pipe *pipealloc(int fdr, int fdw) {
  acquire(&kernpipe.lock);
  struct pipe *pipe = &kernpipe.pipelist[kernpipe.cnt];
  kernpipe.cnt++;
  release(&kernpipe.lock);
  initlock(&pipe->lock, "pipe");
  pipe->readopen = fdr;
  pipe->writeopen = fdw;
  pipe->nread = 0;
  pipe->nwrite = 0;        // TODO
  pipe->readopen = 1;
  pipe->writeopen = 1;
  return pipe;
}

int piperead(struct fd *fd, uint64 buf, uint64 offset, uint64 n) {
  struct proc *p = getproc();
  struct pipe *pipe = fd->pipe;
  acquire(&pipe->lock);
  while (pipe->nread == pipe->nwrite && pipe->writeopen &&
         !pipe->isrm) {        // DOC: pipe-empty
    if (p->killed) {
      release(&pipe->lock);
      return -1;
    }
    sleep(&pipe->nread, &pipe->lock);        // DOC: piperead-sleep
  }
  if (pipe->isrm == 1) {
    release(&pipe->lock);
    return 0;
  }

  uint64 read_size = pipe->nwrite - pipe->nread;        // 实际容量
  read_size = MIN(n, read_size);
  uint64 read_dst = pipe->nread + read_size;

  // 读取数据
  uint64 read_begin = pipe->nread % PIPESIZE;
  uint64 read_end = read_dst % PIPESIZE;

  if (read_size != 0) {
    if (read_begin < read_end) {
      copyout(p->pagetable, (void *)buf, pipe->data + read_begin, read_size);
    } else {
      copyout(p->pagetable, (void *)buf, pipe->data + read_begin,
              PIPESIZE - read_begin);
      copyout(p->pagetable, (void *)buf + PIPESIZE - read_begin, pipe->data,
              read_end);
    }
  }
  pipe->nread += read_size;
  fd->offset += read_size;

  wakeup(&pipe->nwrite);        // DOC: piperead-wakeup
  release(&pipe->lock);
  return read_size;
}

int pipewrite(struct fd *fd, uint64 buf, uint64 offset, uint64 n) {
  struct proc *p = getproc();
  struct pipe *pipe = fd->pipe;
  acquire(&pipe->lock);
  int i = 0;
  while (i < n) {
    if (pipe->isrm || p->killed) {
      release(&pipe->lock);
      return ERR;
    }

    if (pipe->nwrite - pipe->nread == PIPESIZE) {
      wakeup(&pipe->nread);
      sleep(&pipe->nwrite, &pipe->lock);
    } else {
      uint64 left_size = PIPESIZE - (pipe->nwrite - pipe->nread);
      uint64 write_length = MIN(left_size, n);
      uint64 write_dst = pipe->nwrite + write_length;

      uint64 write_begin = pipe->nwrite % PIPESIZE;
      uint64 write_end = write_dst % PIPESIZE;

      if (write_begin < write_end) {
        memcpy(pipe->data + write_begin, (void *)buf + i, write_length);
      } else {
        memcpy(pipe->data + write_begin, (void *)buf + i,
               PIPESIZE - write_begin);
        memcpy(pipe->data, (void *)buf + i + PIPESIZE - write_begin, write_end);
      }
      pipe->nwrite += write_length;
      i += write_length;
    }
  }
  fd->offset += i;
  wakeup(&pipe->nread);
  release(&pipe->lock);
  return i;
}

void pipeclose(struct fd *fd) {
  struct pipe *pi = fd->pipe;
  acquire(&pi->lock);
  if (fd->flags == FS_RDONLY)
    pi->readopen = 0;
  else if (fd->flags == FS_WRONLY)
    pi->writeopen = 0;

  wakeup(&pi->nread);
  wakeup(&pi->nwrite);
  if (pi->readopen == 0 && pi->writeopen == 0) {
    pi->isrm = 1;
    release(&pi->lock);
  } else
    release(&pi->lock);
}

int pipe_check_read(struct pipe *p) {
  acquire(&p->lock);
  if (p->nread != p->nwrite) {
    release(&p->lock);
    return 1;
  } else if (!p->writeopen) {
    release(&p->lock);
    return -1;
  } else {
    release(&p->lock);
    return 0;
  }
}

int pipe_check_write(struct pipe *p) {
  acquire(&p->lock);
  if (p->nwrite - p->nread < PIPESIZE) {
    release(&p->lock);
    return 1;
  } else if (!p->writeopen) {
    release(&p->lock);
    return -1;
  } else {
    release(&p->lock);
    return 0;
  }
}

