  disk.desc[idx[2]].addr = (uint64)&disk.info[idx[0]].status - KVMOFFSET;
  disk.desc[idx[2]].len = 1;
  disk.desc[idx[2]].flags =
      VRING_DESC_F_WRITE;        // device writes the status
  disk.desc[idx[2]].next = 0;

