// uproc.c , defines funcs for user process actions
// all these funcs are working for user api.

// user upt create only has three sources:
//  1. initproc
//  2. execve
//  3. fork
// 1 & 2 need to create upt from zero. 3 just copy the upt.

// userinit, create the first user proc

#define LOADINITPROC(proc, program)                                            \
  ({                                                                           \
    extern char binary_##program[];                                            \
    extern int binary_##program##_size;                                        \
    loadinitproc(proc, binary_##program, binary_##program##_size);             \
  })

void proc_Entry();

void userinit() {
  struct proc *p;

  p = procalloc();
  initproc = p;
  assert(p->pid == 1);
  //分配页表页
  p->pagetable = PtCreate();
  //创建用户栈
  proc_CreateStack(p->pagetable);
  //写入共享内核页
  kvminsert(p->pagetable);
  //设置用户态起始pc与sp
  p->trapframe.epc = UVMBASE;
  p->trapframe.sp = USTACKBASE - PGSIZE;
  //设置内核线程起始pc与sp，以及要切换到的页表
  p->ucontext.ra = (uint64)proc_Entry;
  p->ucontext.sp = p->kstack + PGSIZE;
  p->ucontext.satp = MAKE_SATP(((uint64)p->pagetable - KVMOFFSET));
  //设置文件系统信息初始化
  p->cwdpath[0] = '/';
  fs_initproc(p);
  //进入调度
  procrun(p);
}

int proc_CreateStack(pagetable_t newupt) {
  uint64 base = USTACKSTOP;
  uint64 oa;
  for (; base < USTACKBASE; base += PGSIZE) {
    oa = (uint64)PgAlloc();
    if (oa == 0)
      return ERR;
    memset((void *)oa, 0, PGSIZE);
    if (PtMapPage(newupt, base, oa, PTE_R | PTE_W | PTE_U) != 0) {
      PgFree((void *)oa);
      return ERR;
    }
  }
  return 0;
}

void proc_Entry() {
  struct proc *p = getproc();
  release(&p->lock);
  if (p->pid == 1) {
    FsLoad();
    //加载起始进程
    LOADINITPROC(p, test_busybox);
  }
  sesleep(p, NULL, 1000);
  usertrapret();
}

void proc_FreeUpt(struct proc *p, pagetable_t upt, uint64 oldsz, int perm) {
  if (perm >= 1) {
    proc_mapfree(p);
    TAILQ_INIT(&p->umaphead);
    PtFreeBranch(upt, UMAPBASE, UMAPSTOP);
    PtFreeArea(upt, USTACKSTOP, USTACKSIZE, 0);
  }
  PtFreeArea(upt, UVMBASE, oldsz, 0);
  PgFree((void *)upt);
}

void exit(int status) {
  struct proc *p = getproc();

  if (p == initproc) {
    printf("\ninit exit, stopping system...");
    cpu_halt();
  }

  fs_clearproc(p);
  ProcSigReset(p);
  p->xstatus = status;

  reparent(p);

  //先加入队列，再唤醒父进程，防止lost wakeup
  //需要上proc锁，防止提前释放进程
  acquire(&p->lock);
  acquire(&proc_zombielist.lock);
  p->state = ZOMBIE;
  TAILQ_INSERT_HEAD(&proc_zombielist.list, p, node);
  release(&proc_zombielist.lock);

  wakeup(p->parent);

  CheckAndSwtch((uint64)p->pagetable - KVMOFFSET);

  panic("zombie exit");
}

void reparent(struct proc *p) {
  struct proc *pp;
  for (pp = process; pp < &process[NPROC]; pp++) {
    if (pp->parent == p) {
      if (pp->state == ZOMBIE) {
        acquire(&proc_zombielist.lock);
        procfree(pp);
        release(&proc_zombielist.lock);
      }
      pp->parent = initproc;
      // wakeup(initproc);
    }
  }
}

int fork(uint64 stack) {
  //延时一段时间，见syscall.c说明
  for (int i = 0; i < 15000000; i++) ;

  int i, pid;
  struct proc *newp;
  struct proc *p = getproc();

  if ((newp = procalloc()) == 0) {
    return -1;
  }
  newp->pagetable = PtCreate();
  // 复制数据段
  if (uvmcopy(p->pagetable, newp->pagetable, p->databrk) < 0) {
    newp->state = ZOMBIE;
    acquire(&proc_zombielist.lock);
    procfree(newp);
    release(&proc_zombielist.lock);
    return -1;
  }
  newp->databrk = p->databrk;
  //复制映射段
  MapCopy(p, newp);
  //复制用户态trapframe
  memcpy(&newp->trapframe, &p->trapframe, sizeof(struct trapframe));
  newp->trapframe.a0 = 0;
  if (stack) {
    newp->trapframe.sp = stack;
  }

  //处理fs内容
  for (i = 0; i < NUSERFD; i++) {
    int fdi = p->userfd[i];
    newp->userfd[i] = fdi;
    if (fdi != -1)
      fdrefcnt(fdi, 1);
  }
  newp->rlimit_files_cur = p->rlimit_files_cur;
  newp->rlimit_files_max = p->rlimit_files_max;

  newp->cwd = p->cwd;
  strcpy(newp->cwdpath, p->cwdpath);
  //设置内核线程
  pid = newp->pid;
  newp->ucontext.ra = (uint64)proc_Entry;
  newp->ucontext.sp = newp->kstack + PGSIZE;
  newp->ucontext.satp = MAKE_SATP(((uint64)newp->pagetable - KVMOFFSET));

  newp->parent = p;
  procrun(newp);

  return pid;
}

