#define NSLEEPEVENT 128
// a linkedlist to handle sleep event.
// usedlist is sorted by time
extern statelist_t proc_sleeplist;
extern statelist_t proc_zombielist;

typedef TAILQ_HEAD(, SleepEvent) sleeplist_t;
typedef struct SeList {
  struct spinlock lock;
  sleeplist_t list;
} selist_t;

typedef struct SleepEvent {
  struct proc *p;
  void *se_wchan;
  uint64 se_wakeus;
  TAILQ_ENTRY(SleepEvent) node;
} sleepevent_t;

selist_t SeFreeList;
selist_t SeHandleList;
sleepevent_t SePool[NSLEEPEVENT];

extern struct proc process[NPROC];
extern struct fd kernfd[NKERNFD];

struct spinlock state_lock;

void sleepinit() {
  initlock(&SeFreeList.lock, "selist");
  initlock(&SeHandleList.lock, "selist");
  TAILQ_INIT(&SeFreeList.list);
  TAILQ_INIT(&SeHandleList.list);

  for (int i = NSLEEPEVENT - 1; i >= 0; i--) {
    sleepevent_t *se = &SePool[i];
    se->se_wchan = NULL;
    se->p = NULL;
    TAILQ_INSERT_HEAD(&SeFreeList.list, se, node);
  }
}

sleepevent_t *sealloc(struct proc *p, void *chan, uint64 wakeus) {
  sleepevent_t *se = NULL;
  acquire(&SeFreeList.lock);
  se = TAILQ_FIRST(&SeFreeList.list);
  if (se == NULL) {
    release(&SeFreeList.lock);
    return NULL;
  }
  TAILQ_REMOVE(&SeFreeList.list, se, node);
  release(&SeFreeList.lock);

  se->p = p;
  se->se_wchan = chan;
  se->se_wakeus = wakeus;

  acquire(&SeHandleList.lock);
  if (wakeus) {
    sleepevent_t *tmp = NULL;
    //找到wakeus大于se的第一个元素
    TAILQ_FOREACH(tmp, &SeHandleList.list, node) {
      if (tmp->se_wakeus > wakeus || tmp->se_wakeus == 0)
        break;
    }
    //找到一个有效元素
    if (tmp && tmp->se_wakeus != 0)
      TAILQ_INSERT_AFTER(&SeHandleList.list, tmp, se, node);
    else
      TAILQ_INSERT_TAIL(&SeHandleList.list, se, node);
  } else
    TAILQ_INSERT_TAIL(&SeHandleList.list, se, node);

  //不释放seusedqueue锁
  return se;
}

void sefree(sleepevent_t *se) {
  se->p = NULL;
  se->se_wchan = NULL;
  se->se_wakeus = 0;
  acquire(&SeFreeList.lock);
  TAILQ_INSERT_TAIL(&SeFreeList.list, se, node);
  release(&SeFreeList.lock);
}

void secheck() {
  uint64 curtime = time_mono_us();
  sleepevent_t *se = NULL;
  sleepevent_t *pse = NULL;
  acquire(&SeHandleList.lock);
  TAILQ_FOREACH_SAFE(se, &SeHandleList.list, node, pse) {
    if (se->se_wakeus > curtime || se->se_wakeus == 0)
      break;
    void *chan = se->se_wchan;
    TAILQ_REMOVE(&SeHandleList.list, se, node);
    wakeup(chan);
  }
  release(&SeHandleList.lock);
}

int sesleep(void *chan, struct spinlock *lk, uint64 wakeus) {
  sleepevent_t *se = sealloc(getproc(), chan, wakeus);
  if (lk)
    release(&SeHandleList.lock);
  sleep(chan, lk ? lk : &SeHandleList.lock);
  if (lk)
    acquire(&SeHandleList.lock);
  sefree(se);
  release(&SeHandleList.lock);
  return 0;
}

void sleep(void *chan, struct spinlock *lk) {
  struct proc *p = getproc();
  acquire(&p->lock);
  release(lk);

  acquire(&proc_sleeplist.lock);
  p->sleepchan = chan;
  p->state = SLEEPING;
  TAILQ_INSERT_HEAD(&proc_sleeplist.list, p, node);

  CheckAndSwtch((uint64)p->pagetable - KVMOFFSET);

  p->sleepchan = 0;
  release(&p->lock);
  acquire(lk);
}

void wakeup(void *chan) {
  struct proc *p;
  struct proc *nowp = getproc();
  //下面这段有lost wakeup的bug，找了很久不知道怎么回事
  //因此先用性能慢的代替。
  /*
    struct proc* tmp = 0;
    acquire(&proc_sleeplist.lock);
    TAILQ_FOREACH_SAFE(p,&proc_sleeplist.list,node,tmp) {
      assert(p->state == SLEEPING);
      acquire(&p->lock);
      if (p->sleepchan == chan) {
        TAILQ_REMOVE(&proc_sleeplist.list,p,node);
        procrun(p);
        release(&p->lock);
      }
      else
        release(&p->lock);
    }
    release(&proc_sleeplist.lock);
  */
  for (p = process; p < &process[NPROC]; p++) {
    if(p->pid == 0)continue;
    if (p == nowp)
      continue;
    acquire(&p->lock);
    if (p->state == SLEEPING && p->sleepchan == chan) {
      acquire(&proc_sleeplist.lock);
      TAILQ_REMOVE(&proc_sleeplist.list, p, node);
      release(&proc_sleeplist.lock);
      procrun(p);
    }
    release(&p->lock);
  }
}

