    acquire(&proc_zombielist.lock);
    for (;;) {
      TAILQ_FOREACH(pp, &proc_zombielist.list, node) {
        assert(pp->state == ZOMBIE);
        if (pp->parent == p) {
          acquire(&pp->lock);
          cpid = pp->pid;
          int xstatus = (pp->xstatus << 8);
          procfree(pp);
          release(&pp->lock);
          release(&proc_zombielist.lock);
          copyout(p->pagetable, wstatus, &xstatus, sizeof(int));
          return cpid;
        }
      }
      if (p->killed) {
        release(&proc_zombielist.lock);
        return -1;
      }
      if (option & WNOHANG) {
        release(&proc_zombielist.lock);
        return 0;
      }
      sleep(p, &proc_zombielist.lock);
      if (!havekid(p)) {
        release(&proc_zombielist.lock);
        return -1;
      }
    }
  } else {
    acquire(&proc_zombielist.lock);
    for (;;) {
      acquire(&cp->lock);
      if (cp->state == ZOMBIE) {
        cpid = cp->pid;
        int xstatus = (cp->xstatus << 8);
        procfree(cp);
        release(&cp->lock);
        release(&proc_zombielist.lock);
        copyout(p->pagetable, wstatus, &xstatus, sizeof(int));
        return cpid;
      }
      release(&cp->lock);
      if (p->killed) {
        release(&proc_zombielist.lock);
        return -1;
      }
      if (option & WNOHANG) {
        release(&proc_zombielist.lock);
        return 0;
      }
      sleep(p, &proc_zombielist.lock);
    }
  }
}

