static inline void save_stime(struct proc *p, uint64 cur_us) {
  p->time.tms_stime += cur_us - p->kstarttime;
}

static inline void save_utime(struct proc *p, uint64 cur_us) {
  p->time.tms_utime += cur_us - p->ustarttime;
}

void utime_start(struct proc *p) { p->ustarttime = time_mono_clock(); }

void utime_end(struct proc *p) {
  acquire(&p->lock);
  uint64 cur_us = time_mono_clock();
  save_utime(p, cur_us);
  release(&p->lock);
}

void stime_start(struct proc *p) { p->kstarttime = time_mono_clock(); }

void stime_end(struct proc *p) {
  acquire(&p->lock);
  uint64 cur_us = time_mono_clock();
  save_stime(p, cur_us);
  release(&p->lock);
}

// Mutual exclusion spin locks.

#include "types.h"
#include "param.h"
#include "memlayout.h"
#include "lib/locks.h"
#include "riscv.h"
#include "proc/proc.h"
#include "defs.h"

void initlock(struct spinlock *lk, char *name) {
  lk->name = name;
  lk->locked = 0;
  lk->cpu = 0;
}

// Acquire the lock.
// Loops (spins) until the lock is acquired.
void acquire(struct spinlock *lk) {
  push_off();        // disable interrupts to avoid deadlock.
  if (holding(lk)) {
    // backtrace();
    printf("lock name : %s ,", lk->name);
    panic("acquire");
  }

  // On RISC-V, sync_lock_test_and_set turns into an atomic swap:
  //   a5 = 1
  //   s1 = &lk->locked
  //   amoswap.w.aq a5, a5, (s1)
  while (__sync_lock_test_and_set(&lk->locked, 1) != 0)
    ;

  // Tell the C compiler and the processor to not move loads or stores
  // past this point, to ensure that the critical section's memory
  // references happen strictly after the lock is acquired.
  // On RISC-V, this emits a fence instruction.
  __sync_synchronize();

  // Record info about lock acquisition for holding() and debugging.
  lk->cpu = getcpu();
}

// Release the lock.
void release(struct spinlock *lk) {
  if (!holding(lk)) {
    struct cpu *cpu1 = getcpu();
    struct cpu *cpu2 = lk->cpu;
    backtrace();
    printf("lock name : %s ,", lk->name);
    printf("\n%x %x\n", cpu1, cpu2);
    panic("release");
  }

  lk->cpu = 0;

  // Tell the C compiler and the CPU to not move loads or stores
  // past this point, to ensure that all the stores in the critical
  // section are visible to other CPUs before the lock is released,
  // and that loads in the critical section occur strictly before
  // the lock is released.
  // On RISC-V, this emits a fence instruction.
  __sync_synchronize();

  // Release the lock, equivalent to lk->locked = 0.
  // This code doesn't use a C assignment, since the C standard
  // implies that an assignment might be implemented with
  // multiple store instructions.
  // On RISC-V, sync_lock_release turns into an atomic swap:
  //   s1 = &lk->locked
  //   amoswap.w zero, zero, (s1)
  __sync_lock_release(&lk->locked);

  pop_off();
}

// Check whether this cpu is holding the lock.
// Interrupts must be off.
int holding(struct spinlock *lk) {
  int r;
  r = (lk->locked && lk->cpu == getcpu());
  return r;
}

// push_off/pop_off are like intr_off()/intr_on() except that they are matched:
// it takes two pop_off()s to undo two push_off()s.  Also, if interrupts
// are initially off, then push_off, pop_off leaves them off.

void push_off(void) {
  int old = intr_get();

  intr_off();
  if (getcpu()->noff == 0)
    getcpu()->intena = old;
  getcpu()->noff += 1;
}

void pop_off(void) {
  struct cpu *c = getcpu();
  if (intr_get())
    panic("pop_off - interruptible");
  if (c->noff < 1)
    panic("pop_off");
  c->noff -= 1;
  if (c->noff == 0 && c->intena)
    intr_on();
}

// Sleeping locks

#include "types.h"
#include "riscv.h"
#include "defs.h"
#include "param.h"
#include "memlayout.h"
#include "lib/locks.h"
#include "proc/proc.h"

void initsleeplock(struct sleeplock *lk, char *name) {
  initlock(&lk->lk, "sleep lock");
  lk->name = name;
  lk->locked = 0;
  lk->pid = 0;
}

void acquiresleep(struct sleeplock *lk) {
  acquire(&lk->lk);
  while (lk->locked) {
    sleep(lk, &lk->lk);
  }
  lk->locked = 1;
  lk->pid = getproc()->pid;
  release(&lk->lk);
}

void releasesleep(struct sleeplock *lk) {
  acquire(&lk->lk);
  lk->locked = 0;
  lk->pid = 0;
  wakeup(lk);
  release(&lk->lk);
}

int holdingsleep(struct sleeplock *lk) {
  int r;

  acquire(&lk->lk);
  r = lk->locked && (lk->pid == getproc()->pid);
  release(&lk->lk);
  return r;
}

