struct {
  sigaction_t sigacts[NPROC][SIGNAL_MAX];
  sigevent_t sigevents[SIGNAL_MAX];
  sigeventq_t sigevent_freeq;
  struct spinlock lock;
} sigpool;

extern struct proc process[NPROC];

void SigInit() {
  initlock(&sigpool.lock, "sigaction");
  TAILQ_INIT(&sigpool.sigevent_freeq);
  for (int i = SIGNAL_MAX - 1; i >= 0; i--) {
    TAILQ_INSERT_HEAD(&sigpool.sigevent_freeq, &sigpool.sigevents[i], node);
  }
  // memset(sigpool.sigacts, 0, sizeof(sigaction_t) * SIGNAL_MAX * NPROC);
}

sigevent_t *SigEventAlloc(int signo) {
  acquire(&sigpool.lock);
  sigevent_t *se = TAILQ_FIRST(&sigpool.sigevent_freeq);
  assert(se != NULL);
  TAILQ_REMOVE(&sigpool.sigevent_freeq, se, node);
  release(&sigpool.lock);
  se->se_signo = signo;
  return se;
}

void SigEventFree(sigevent_t *se) {
  acquire(&sigpool.lock);
  memset(se, 0, sizeof(sigevent_t));
  TAILQ_INSERT_HEAD(&sigpool.sigevent_freeq, se, node);
  release(&sigpool.lock);
}

int SigActRegister(int signum, uint64 act, uint64 oldact, int sigset_size) {
  assert(0 < signum && signum <= SIGNAL_MAX);
  struct proc *p = getproc();
  sigaction_t *kact = &sigpool.sigacts[p - process][signum - 1];
  size_t ksa_size = sizeof(sigaction_t) - sizeof(sigset_t) + sigset_size;

  if (oldact != 0)
    copyout(p->pagetable, (void *)oldact, (void *)kact, ksa_size);
  if (act != 0) {
    memset((void *)kact, 0, sizeof(sigaction_t));
    memcpy((void *)kact, (void *)act, ksa_size);
    if (!(kact->sa_flags & SA_RESTORER)) {
      kact->sa_restorer = 0;
    }
  }
  return 0;
}

void SigActMask(int how, sigset_t newkset, size_t sigsetsize) {
  struct proc *p = getproc();
  int len = MIN(sizeof(p->sigmask.ss_byte), sigsetsize);
  switch (how) {
  case SIG_BLOCK:
    for (int i = 0; i < len; i++) {
      p->sigmask.ss_byte[i] |= newkset.ss_byte[i];
    }
    break;
  case SIG_UNBLOCK:
    for (int i = 0; i < len; i++) {
      p->sigmask.ss_byte[i] &= ~newkset.ss_byte[i];
    }
    break;
  case SIG_SETMASK:
    for (int i = 0; i < len; i++) {
      p->sigmask.ss_byte[i] = newkset.ss_byte[i];
    }
    break;
  }
}

void SigActFree(struct proc *p) {
  memset(&sigpool.sigacts[p - process], 0, sizeof(sigpool.sigacts[0]));
}

void SigActCopy(struct proc *p, struct proc *childp) {
  memcpy(&sigpool.sigacts[childp - process], &sigpool.sigacts[p - process],
         sizeof(sigpool.sigacts[0]));
}

sigaction_t *SigActGet(struct proc *p, int signo) {
  assert(0 < signo && signo <= SIGNAL_MAX);
  return &sigpool.sigacts[p - process][signo - 1];
}

sigevent_t *SigEventFetch(struct proc *p) {
  sigevent_t *se = NULL;
  TAILQ_FOREACH(se, &p->sigqueue, node) {
    if (!isSigMasked(p, se->se_signo))
      return se;
  }
  return NULL;
}

