struct {
  TAILQ_HEAD(, itimer) FreeList;
  itimer_t itimer[NPROC * 2];
  struct spinlock lock;
} itimerPool;

TAILQ_HEAD(, itimer) itimerList;
struct spinlock itimerListLock;

void itimerInit() {
  TAILQ_INIT(&itimerPool.FreeList);
  TAILQ_INIT(&itimerList);
  for (int i = NPROC * 2 - 1; i >= 0; i--) {
    TAILQ_INSERT_HEAD(&itimerPool.FreeList, &itimerPool.itimer[i], node);
  }
  initlock(&itimerPool.lock, "itimerfreeq");
  initlock(&itimerListLock, "itimerlist");
}

static itimer_t *itimerAlloc() {
  acquire(&itimerPool.lock);
  itimer_t *itimer = TAILQ_FIRST(&itimerPool.FreeList);
  assert(itimer != NULL);
  TAILQ_REMOVE(&itimerPool.FreeList, itimer, node);
  release(&itimerPool.lock);
  return itimer;
}

static void itimerFree(itimer_t *itimer) {
  acquire(&itimerPool.lock);
  memset(itimer, 0, sizeof(itimer_t));
  TAILQ_INSERT_HEAD(&itimerPool.FreeList, itimer, node);
  release(&itimerPool.lock);
}

static void CycleToTimeval(uint64 cycles, struct timeval *val) {
  val->tv_usec = (cycles / CLOCK_PER_USEC) % USEC_PER_SEC;
  val->tv_sec = cycles / CLOCK_PER_SEC;
}

static uint64 TimevalToCycle(struct timeval *val) {
  return val->tv_sec * CLOCK_PER_SEC + val->tv_usec * CLOCK_PER_USEC;
}

/// @note 需要持有itimerListLock锁
static void _itimerRemove(struct proc *p) {
  assert(itimerListLock.locked);

  itimer_t *itimer = p->itimer;
  TAILQ_REMOVE(&itimerList, itimer, node);
  itimerFree(itimer);
}

void itimerGet(struct proc *p, itimerval_t *itv) {
  acquire(&itimerPool.lock);
  itimer_t *itimer = p->itimer;
  if (itimer != NULL) {
    CycleToTimeval(itimer->interval, &itv->it_interval);
    CycleToTimeval(itimer->start + itimer->duration - time_rtc_clock(),
                   &itv->it_value);
  } else {
    CycleToTimeval(0, &itv->it_interval);
    CycleToTimeval(0, &itv->it_value);
  }
  release(&itimerPool.lock);
}

// what behavior???
void itimerSet(struct proc *p, struct itimerval *itv) {
  struct itimer *itimer = itimerAlloc();
  uint64 start = time_rtc_clock();
  uint64 duration = TimevalToCycle(&itv->it_value);
  uint64 interval = TimevalToCycle(&itv->it_interval);

  if (p->itimer != NULL) {
    acquire(&itimerListLock);
    if (duration == 0)
      _itimerRemove(p);
    else {
      itimer->start = start;
      itimer->duration = duration;
    }
    itimer->interval = interval;
    release(&itimerListLock);
  } else {
    struct itimer *itimer = itimerAlloc();
    itimer->start = start;
    itimer->duration = duration;
    itimer->interval = interval;
    itimer->process = p;
    acquire(&itimerListLock);
    TAILQ_INSERT_HEAD(&itimerList, itimer, node);
    release(&itimerListLock);
  }
}

void itimerRemove(struct proc *p) {
  acquire(&itimerListLock);
  _itimerRemove(p);
  release(&itimerListLock);
}

void itimerCheck() {
  uint64 now = time_rtc_clock();
  itimer_t *itimer;
  itimer_t *toDel = NULL;
  acquire(&itimerListLock);
  TAILQ_FOREACH(itimer, &itimerList, node) {
    if (itimer->start + itimer->duration <= now) {
      SigSend(itimer->process, SIGALRM);
      if (itimer->interval != 0) {
        itimer->duration = itimer->interval;
        itimer->start = now;
      } else {
        if (toDel != NULL)
          _itimerRemove(toDel->process);
        toDel = itimer;
      }
    }
  }
  if (toDel != NULL)
    _itimerRemove(toDel->process);
  release(&itimerListLock);
}

