  int i;
  for (i = 0; i < n; i++) {
    if (is_blocked) {
      break;
    }

    // 如果没读到字符，cons_getc 会返回255
    while ((ch = consgetc()) == (char)255) {
      yield();
      is_blocked = 1;
    }
    copyout(getproc()->pagetable, (void *)(buf + i), &ch, 1);
  }
  return i;
}

#define WRITE_MAX_PER_TIME 1024
int consolewrite(uint64 buf, uint64 n) {
  char s[WRITE_MAX_PER_TIME + 1];

  for (int i = 0; i <= n; i += WRITE_MAX_PER_TIME) {
    int len = MIN(WRITE_MAX_PER_TIME, n - i);
    memcpy(s, (void *)buf + i, len);
    s[len] = 0;

    // 需要在copyIn之后再printf输出，防止先获取pr_lock造成死锁
    printf("%s", s);
  }

  return n;
}

