// 初始化

// fill in superblock
int clusinit(struct FileSystem *fs) {
  struct buf *buf = bread(fs->deviceNumber, 0);
  if (buf == NULL)
    return ERR;
  struct fat32hdr *hdr = (struct fat32hdr *)(buf->data);
  memcpy(&fs->superblock, hdr, sizeof(*hdr));

  if (strncmp((char const *)(buf->data + 82), "FAT32", 5))
    panic("not FAT32 volume");
  if (strncmp((char const *)(fs->superblock.BS_FilSysType), "FAT32", 5))
    panic("read fat32hdr error");

  fs->sbinfo.EX_FirstDataSec =
      hdr->BPB_RsvdSecCnt + hdr->BPB_NumFATs * hdr->BPB_FATSz32;
  fs->sbinfo.EX_DataSecCnt = hdr->BPB_TotSec32 - fs->sbinfo.EX_FirstDataSec;
  fs->sbinfo.EX_DataClusCnt = fs->sbinfo.EX_DataSecCnt / hdr->BPB_SecPerClus;
  fs->sbinfo.EX_BytesPerClus = hdr->BPB_SecPerClus * hdr->BPB_BytsPerSec;
  printf("fsdata:\n");
  printf("bytes per clus:%d\n", fs->sbinfo.EX_BytesPerClus);
  printf("bytes per sec:%d\n", fs->superblock.BPB_BytsPerSec);

  if (BSIZE != fs->superblock.BPB_BytsPerSec) {
    return ERR;
  }
  brelse(buf);
  return 0;
}

// fat表处理
// read a fat entry and returns the next clusNo
uint32 fatread(struct FileSystem *fs, uint64 clusNo) {
  if (clusNo < 2 || clusNo > fs->sbinfo.EX_DataClusCnt + 1)
    return 0;
  uint64 secNo = clusFatSecNo(fs, clusNo, 0);
  // uint64 secNo2 = clusFatSecNo(fs,clusNo,1);
  uint64 secOff = clusFatSecOffset(fs, clusNo);

  struct buf *buf = bread(fs->deviceNumber, secNo);
  uint32 *fat = (uint32 *)buf->data;
  uint32 ret = fat[secOff];
  brelse(buf);

  return ret;
}
// write nextNo to the fat entry of clusNo
void fatwrite(struct FileSystem *fs, uint64 clusNo, uint32 nextNo) {
  if (clusNo < 2 || clusNo > fs->sbinfo.EX_DataClusCnt + 1)
    panic("fatwrite error");
  uint64 secNo1 = clusFatSecNo(fs, clusNo, 0);
  uint64 secNo2 = clusFatSecNo(fs, clusNo, 1);
  uint64 secOff = clusFatSecOffset(fs, clusNo);

  struct buf *buf1 = bread(fs->deviceNumber, secNo1);
  uint32 *fat1 = (uint32 *)buf1->data;
  fat1[secOff] = nextNo;
  bwrite(buf1);
  brelse(buf1);
  struct buf *buf2 = bread(fs->deviceNumber, secNo2);
  uint32 *fat2 = (uint32 *)buf2->data;
  fat2[secOff] = nextNo;
  bwrite(buf2);
  brelse(buf2);

