static int _sys_kill(int pid, int sig) {
  if (sig < 0 || sig >= SIGNAL_MAX)
    return -EINVAL;

  struct proc *p;
  if (pid == 0)
    p = getproc();
  else
    p = getprocbypid(pid);

  if (p == NULL)
    return -ESRCH;
  if (sig == 0)
    return 0;

  // busybox 特判？
  SigSend(p, sig);
  return 0;
}

static int _sys_sigaction(int signum, uint64 act, uint64 oldact,
                          int sigset_size) {
  if (signum < 0 || signum >= SIGNAL_MAX)
    return -EINVAL;
  else
    return SigActRegister(signum, act, oldact, sigset_size);
}

static int _sys_sigreturn() {
  struct proc *p = getproc();
  // siginfo
  SigRet();
  return p->trapframe.a0;
}

static int _sys_sigprocmask(int how, uint64 set, uint64 oldset,
                            size_t sigsetsize) {
  if (sigsetsize > sizeof(sigset_t))
    return -EINVAL;
  sigset_t newkset;
  struct proc *p = getproc();
  if (set != 0)
    memcpy(&newkset, (void *)set, sizeof(sigset_t));
  acquire(&p->lock);
  if (oldset != 0)
    copyout(p->pagetable, (void *)oldset, &p->sigmask, sizeof(sigset_t));
  if (set != 0)
    SigActMask(how, newkset, sigsetsize);
  release(&p->lock);
  return 0;
}

static int _sys_sigsuspend(uint64 usigset) {
  sigset_t sigset;
  sigevent_t *se;
  struct proc *p = getproc();
  memset(&sigset, 0, sizeof(sigset_t));
  // length not known
  if (usigset != 0)
    memcpy(&sigset, (void *)usigset, sizeof(sigset_t));
  acquire(&p->lock);
  memcpy(&p->sigmask, &sigset, sizeof(sigset_t));

  while ((se = SigEventFetch(p)) == NULL) {
    release(&p->lock);
    yield();
    acquire(&p->lock);
  }
  assert(!isSigMasked(p, se->se_signo));
  return 0;
}

