static int _sys_setitimer(int which, uint64 new_value, uint64 old_value) {
  struct itimerval new, old;
  struct proc *p = getproc();
  if (old_value) {
    itimerGet(p, &old);
    copyout(p->pagetable, (void *)old_value, &old, sizeof(struct itimerval));
  }
  if (new_value) {
    memcpy(&new, (void *)new_value, sizeof(struct itimerval));
    itimerSet(p, &new);
  }
  return 0;
}

static int _sys_getitimer(int which, uint64 curr_value) {
  struct itimerval curr;
  struct proc *p = getproc();
  itimerGet(p, &curr);
  copyout(p->pagetable, (void *)curr_value, &curr, sizeof(struct itimerval));
  return 0;
}

static int _sys_sigtimedwait(uint64 usigset, uint64 uinfo, uint64 utimeout) {
  struct proc *p = getproc();
  sigset_t sigset = {0};
  if (usigset) {
    memcpy(&sigset, (void *)usigset, sizeof(sigset_t));
  }
  timespec_t timeout = {0};
  if (utimeout) {
    memcpy(&timeout, (void *)utimeout, sizeof(timespec_t));
  }
  siginfo_t info = {0};
  sig_timedwait(&sigset, &info, TS2USEC(timeout) / 1000);
  if (uinfo) {
    copyout(p->pagetable, (void *)uinfo, &info, sizeof(siginfo_t));
  }
  return 0;
}

