void backtrace(void) {
  printf("backtrace:\n");
  uint64 fp = r_fp();
  int layer = 8;
  while (PGROUNDUP(fp) - PGROUNDDOWN(fp) == PGSIZE) {
    uint64 ret_addr = *(uint64 *)(fp - 8);
    printf("%p\n", ret_addr);
    fp = *(uint64 *)(fp - 16);
    layer--;
    if (!layer)
      break;
  }
}

