static inline void FD_CLR(int fd, fd_set *set) {
  set->fds_bits[fd / (8 * sizeof(long))] &= ~(1UL << (fd % (8 * sizeof(long))));
}

#define FD_SET_FOREACH(fd, set)                                                \
  for (fd = 0; fd < FD_SETSIZE; fd++)                                          \
    if (FD_ISSET(fd, set))

